export const FACTS: Fact[] = [
  { country: "cz", year: 1930, category: "Culture", text: "The Villa Tugendhat in Brno, designed by Mies van der Rohe with a glowing onyx wall and floor-to-ceiling windows that sank entirely into the floor, was completed as one of the world's purest statements of functionalist architecture." },
  { country: "cz", year: 1930, category: "Politics", text: "The eighty-year-old founding president Tomáš Garrigue Masaryk, revered as the philosopher-statesman who had built the republic, presided over what was then the only stable parliamentary democracy in Central Europe." },
  { country: "cz", year: 1931, category: "Science & tech", text: "Polarography, the electrochemical analysis technique invented by chemist Jaroslav Heyrovský using a dripping mercury electrode, was spreading into laboratories worldwide and would one day earn him a Nobel Prize." },
  { country: "cz", year: 1932, category: "People", text: "Tomáš Baťa, the shoe magnate and mayor of Zlín whose factory empire was the largest of its kind on earth, was killed at fifty-six when his Junkers aircraft crashed in dense fog shortly after takeoff." },
  { country: "cz", year: 1932, category: "Culture", text: "Director Miloš Forman, the future maker of \"One Flew Over the Cuckoo's Nest\" and \"Amadeus,\" was born in February into a country whose own cinema was just finding its voice." },
  { country: "cz", year: 1933, category: "Culture", text: "Gustav Machatý's film \"Ecstasy,\" featuring eighteen-year-old Hedy Kiesler running bare-chested through a forest and an unprecedented depiction of orgasm, premiered in Prague and scandalized audiences across the world." },
  { country: "cz", year: 1933, category: "Everyday life", text: "At the depth of the Great Depression unemployment peaked at around 920,000 people in February, bringing ubiquitous layoffs and hardship to industrial towns and cities." },
  { country: "cz", year: 1933, category: "Sport", text: "At the ice hockey world championships held in Prague the home team took bronze and was crowned European champion, igniting a national passion for the sport that would never fade." },
  { country: "cz", year: 1933, category: "Politics", text: "Adolf Hitler's rise to power across the border sent a wave of dread through the country, whose three-million-strong German minority along the frontier became a growing source of anxiety." },
  { country: "cz", year: 1934, category: "Sport", text: "The national football team, led by the legendary goalkeeper and captain František Plánička, reached the World Cup final in Rome and lost 2–1 to Italy in extra time after leading late in the match." },
  { country: "cz", year: 1934, category: "Science & tech", text: "Škoda introduced the affordable 418 Popular, built on an innovative backbone-tube chassis, putting motoring within reach of more families and helping the company climb toward market leadership." },
  { country: "cz", year: 1934, category: "Culture", text: "The comic duo Jiří Voskovec and Jan Werich of Prague's avant-garde Liberated Theatre brought their satirical wit to the screen in the hit comedy \"Hej-Rup!\"" },
  { country: "cz", year: 1935, category: "Politics", text: "In the parliamentary election Konrad Henlein's Sudeten German Party, secretly funded from Berlin, won the single largest share of votes at 15.2 percent, capturing roughly two-thirds of the ethnic German vote." },
  { country: "cz", year: 1935, category: "Politics", text: "The ailing Masaryk resigned the presidency in December and was succeeded by his longtime foreign minister Edvard Beneš, the architect of the republic's system of Western alliances." },
  { country: "cz", year: 1935, category: "Politics", text: "A mutual-assistance treaty was signed with the Soviet Union, though its terms made Soviet aid conditional on France acting first to defend the country." },
  { country: "cz", year: 1936, category: "Culture", text: "Karel Čapek published \"War with the Newts,\" a savage satirical allegory of fascism and human greed that cemented his standing as a Nobel-nominated writer and the man who had given the world the word \"robot.\"" },
  { country: "cz", year: 1936, category: "People", text: "Václav Havel, the future dissident playwright who would become the country's first post-communist president, was born on 5 October in Prague to a prosperous family." },
  { country: "cz", year: 1937, category: "Culture", text: "Hugo Haas directed the screen version of Čapek's anti-fascist play \"The White Disease,\" while Voskovec and Werich's \"The World Belongs to Us\" took aim at dictatorship, both films soon banned by the Nazis." },
  { country: "cz", year: 1937, category: "People", text: "Tomáš Garrigue Masaryk, the beloved \"president-liberator\" who had embodied the young democracy, died in September at the age of eighty-seven and was mourned by the entire nation." },
  { country: "cz", year: 1938, category: "Sport", text: "Prague's Štvanice Stadium hosted the ice hockey world championships in February, where the home side beat Germany 3–0 to claim bronze before tens of thousands of fans." },
  { country: "cz", year: 1938, category: "Upheaval", text: "On 23 September a decree of general mobilization summoned the army to man the nation's modern frontier fortifications, and within a day around a million men reported for duty to defend the borders." },
  { country: "cz", year: 1938, category: "Upheaval", text: "In the small hours of 30 September Hitler, Chamberlain, Mussolini and Daladier signed the Munich Agreement, handing the Sudeten borderlands to Germany without a single representative of the betrayed country present." },
  { country: "cz", year: 1938, category: "People", text: "Karel Čapek, who had refused exile despite being branded \"public enemy number two\" by the Gestapo, died of pneumonia on Christmas Day, broken in spirit by the dismemberment of his homeland." },
  { country: "cz", year: 1939, category: "Upheaval", text: "On the night of 14–15 March the elderly President Emil Hácha, threatened with the bombing of Prague, collapsed and then signed away his country's independence in Berlin as German troops poured across the frontier." },
  { country: "cz", year: 1939, category: "Upheaval", text: "On 16 March Hitler proclaimed the Protectorate of Bohemia and Moravia from Prague Castle, reducing the Czech lands to a powerless component of the Reich and snuffing out two decades of democracy." },
  { country: "cz", year: 1940, category: "People", text: "Flying with the Polish No. 303 Squadron over southern England, the Czech ace Josef Frantisek shot down seventeen German aircraft in barely four weeks to become the top-scoring Allied pilot of the Battle of Britain, only to die in a crash that October." },
  { country: "cz", year: 1940, category: "Upheaval", text: "Exiled airmen formed No. 310 Squadron at Duxford that July and, within a single month of training, hurled themselves into the Battle of Britain as part of the Duxford Big Wing, claiming dozens of enemy aircraft." },
  { country: "cz", year: 1940, category: "Culture", text: "Occupiers seized the gleaming Barrandov film studios outside Prague and turned them into a back lot for Goebbels's propaganda machine, where the notorious antisemitic feature Jud Suss was among the productions shot that year." },
  { country: "cz", year: 1940, category: "Everyday life", text: "Under tightening rationing, townspeople queued for hours for a single loaf of bread or a sliver of meat, while Jewish residents were barred from restaurants and cinemas and allowed to shop for only one hour a day." },
  { country: "cz", year: 1941, category: "Politics", text: "Reinhard Heydrich arrived as acting Reich Protector on 27 September, immediately declaring martial law and arresting Prime Minister Alois Elias, who was swiftly sentenced to death for his secret links to the resistance." },
  { country: "cz", year: 1941, category: "Upheaval", text: "On 24 November the first transport of 342 Jewish men reached the fortress town of Terezin, opening a ghetto through which some 140,000 people would pass and from which tens of thousands were sent on to the death camps." },
  { country: "cz", year: 1941, category: "People", text: "Vaclav Klaus, the future economist who would become independent Czechia's first prime minister and later its president, was born in Prague's Vinohrady district during the Nazi occupation on 19 June." },
  { country: "cz", year: 1942, category: "Upheaval", text: "On 27 May, parachutists Jozef Gabcik and Jan Kubis ambushed Heydrich's open-top Mercedes in Prague, mortally wounding the Reich Protector, who died of his injuries eight days later." },
  { country: "cz", year: 1942, category: "Upheaval", text: "In savage reprisal, on 10 June the village of Lidice was razed to the ground, its men shot and its women and children deported, followed two weeks later by the destruction of the hamlet of Lezaky." },
  { country: "cz", year: 1943, category: "Culture", text: "Imprisoned in the Terezin ghetto, children rehearsed and performed Hans Krasa's children's opera Brundibar dozens of times, its tale of a defeated bully offering fleeting hope amid the endless deportations to Auschwitz." },
  { country: "cz", year: 1944, category: "Culture", text: "The SS choreographed a 'beautified' Terezin for a Red Cross delegation that visited on 23 June, complete with fresh paint, a football match and a staged Brundibar performance, then filmed the deception for a propaganda movie before sending most of the cast to their deaths." },
  { country: "cz", year: 1945, category: "Upheaval", text: "The Prague Uprising erupted on 5 May with more than two thousand barricades thrown up across the city, and after days of bitter street fighting the capital was liberated as the Red Army rolled in on 9 May." },
  { country: "cz", year: 1945, category: "Politics", text: "President Edvard Benes re-entered Prague on 16 May to jubilant crowds, the only Eastern European exile leader allowed to return and resume his post after the war." },
  { country: "cz", year: 1945, category: "Politics", text: "By presidential decrees of 24 October, mines, banks, insurance firms and large industrial enterprises were nationalised in one sweep, placing nearly two-thirds of industry under state control." },
  { country: "cz", year: 1946, category: "Politics", text: "In free elections on 26 May the Communist Party took 38 percent of the vote, more than any party had ever won, and its leader Klement Gottwald became prime minister of a National Front coalition that July." },
  { country: "cz", year: 1946, category: "Everyday life", text: "The state-led expulsion of around three million ethnic Germans, sanctioned at Potsdam, emptied the borderlands and was followed by a wave of resettlers moving into the abandoned Sudeten farms and towns." },
  { country: "cz", year: 1947, category: "Politics", text: "Foreign Minister Jan Masaryk and other leaders wanted to join the American Marshall Plan, but Stalin summoned them to Moscow and forced the government to reject the aid on 10 July." },
  { country: "cz", year: 1947, category: "Upheaval", text: "A ferocious drought stretching from April to October withered the cereal harvest, leaving the country dependent on politically motivated grain shipments from a Soviet Union itself gripped by famine." },
  { country: "cz", year: 1947, category: "Culture", text: "Jiri Trnka released his first feature-length puppet film, The Czech Year (Spalicek), a lyrical cycle of village customs and seasons that won the Gold Medal at Venice and made his name in animation." },
  { country: "cz", year: 1947, category: "Sport", text: "The national ice hockey team captured its first world championship on home ice in Prague in February, announcing itself as a dominant force in European hockey." },
  { country: "cz", year: 1948, category: "Politics", text: "In late February the Communists seized full control of the state, and on 25 February a cornered President Benes accepted a cabinet on their terms, beginning four decades of one-party rule." },
  { country: "cz", year: 1948, category: "People", text: "On 10 March, Foreign Minister Jan Masaryk, son of the republic's founder, was found dead beneath the windows of his apartment, a death officially ruled suicide but long shadowed by suspicion of murder." },
  { country: "cz", year: 1948, category: "Sport", text: "At the London Olympics, Emil Zatopek won gold in the 10,000 metres, lapping all but two rivals, and took silver in the 5,000 metres only weeks after racing the longer distance for just the second time in his life." },
  { country: "cz", year: 1948, category: "Everyday life", text: "At the eleventh all-Sokol gymnastics festival in Prague that summer, some 150,000 adults performed mass calisthenics before crowds, and many marchers turned the parade into open protest against the new regime, for which thousands were later persecuted." },
  { country: "cz", year: 1949, category: "Everyday life", text: "The shoemaking giant Bata, already nationalised, saw its hometown of Zlin renamed Gottwaldov after the Communist president, erasing the founder's name from the map of the 'city built on shoes'." },
  { country: "cz", year: 1949, category: "Sport", text: "Having lost six players when their plane vanished over the English Channel the previous November, the grieving national hockey side rallied to win the world championship in Stockholm in February." },
  { country: "cz", year: 1950, category: "Politics", text: "On 27 June the democratic politician and lawyer Milada Horáková was hanged at Prague's Pankrác prison after a scripted, radio-broadcast show trial, becoming the only woman the Communist regime executed for political reasons despite protests from Albert Einstein, Winston Churchill and Eleanor Roosevelt." },
  { country: "cz", year: 1950, category: "Sport", text: "In March the secret police arrested the players of the world-champion national ice hockey team, and after a show trial sent stars like goalkeeper Bohumil Modrý to the uranium camps of Jáchymov, where exposure to radiation later cost several of them their lives." },
  { country: "cz", year: 1951, category: "Upheaval", text: "The authorities launched 'Operation Kulak,' forcibly evicting around 4,000 prosperous farming families from their land and homes as part of the violent drive to herd peasants into collective farms." },
  { country: "cz", year: 1952, category: "Sport", text: "At the Helsinki Olympics the soldier-runner Emil Zátopek achieved a feat never repeated, winning gold in the 5,000 metres, the 10,000 metres and, on a whim in his very first attempt, the marathon." },
  { country: "cz", year: 1952, category: "Politics", text: "In the antisemitic Slánský trial, fourteen senior Communists, eleven of them of Jewish origin, were convicted of a fictitious 'Zionist conspiracy,' and on 3 December eleven were hanged at Pankrác, including the party's own former General Secretary Rudolf Slánský." },
  { country: "cz", year: 1953, category: "Everyday life", text: "The brutal currency reform of 1 June wiped out cash savings at a rate of fifty old crowns to one new one, abolished state debts overnight, and ended the rationing system that had kept food cheap." },
  { country: "cz", year: 1953, category: "Upheaval", text: "When the currency reform was announced, thousands of people, mostly Škoda workers, rose up in Plzeň, building barricades and tearing down Communist symbols in a workers' revolt that preceded the larger East German uprising two weeks later." },
  { country: "cz", year: 1953, category: "Politics", text: "Hardline President Klement Gottwald died on 14 March, just days after returning from Stalin's funeral in Moscow, and was succeeded by the former trade-union leader Antonín Zápotocký." },
  { country: "cz", year: 1953, category: "Culture", text: "On 1 May the country's first television broadcast went out from Studio Prague, opening with a short performance by the actor František Filipovský transmitted in black-and-white to a mere handful of receivers." },
  { country: "cz", year: 1954, category: "Culture", text: "Director Otakar Vávra released 'Jan Hus,' the first part of his lavish Hussite Revolutionary Trilogy and the most expensive native film project to date, retelling the burning of the medieval reformer at the stake in 1415." },
  { country: "cz", year: 1955, category: "Everyday life", text: "On 1 May a 15.5-metre granite colossus of Stalin leading the workers, the largest statue of the dictator on earth, was unveiled on Letná Hill above Prague, its sculptor Otakar Švec having taken his own life days before the ceremony." },
  { country: "cz", year: 1955, category: "Sport", text: "The first Spartakiad, a mass display of synchronised gymnastics drawing huge numbers of performers, filled Prague's vast Strahov Stadium on 23 June, repurposing the banned Sokol movement's traditions for Communist spectacle." },
  { country: "cz", year: 1955, category: "Politics", text: "After Stalin's and Gottwald's deaths a January amnesty freed the imprisoned national hockey players, though many emerged from the uranium mines with ruined health." },
  { country: "cz", year: 1956, category: "Science & tech", text: "The Tatra company unveiled the streamlined, rear-engined Tatra 603, an air-cooled V8 luxury saloon reserved almost exclusively for high-ranking party officials and factory bosses." },
  { country: "cz", year: 1956, category: "People", text: "The future tennis champion Martina Navratilova was born in Prague on 18 October, about two decades before she would defect to the United States and rewrite the record books at Wimbledon." },
  { country: "cz", year: 1956, category: "Culture", text: "Otakar Vávra completed his Hussite epic with 'Jan Žižka,' glorifying the one-eyed medieval warlord as a forerunner of revolutionary struggle in line with official ideology." },
  { country: "cz", year: 1957, category: "Culture", text: "Animator Zdeněk Miler's first Little Mole film, 'How the Mole Got His Trousers,' won a Silver Lion at the Venice Film Festival and launched a beloved, near-wordless cartoon character known across the world." },
  { country: "cz", year: 1957, category: "Politics", text: "President Antonín Zápotocký died of a heart attack on 13 November, and the Stalinist party chief Antonín Novotný seized the presidency as well, concentrating both top offices in his own hands." },
  { country: "cz", year: 1957, category: "Sport", text: "Emil Zátopek, the 'Czech Locomotive,' retired from competitive running, leaving behind four Olympic gold medals and a long string of world records in distance events." },
  { country: "cz", year: 1958, category: "Culture", text: "At the Brussels Expo 58 the Czechoslovak pavilion was judged the finest of the fair, and its dazzling Laterna Magika show, blending live actors with projected film under Alfréd Radok and designer Josef Svoboda, gave the world its first taste of multimedia theatre." },
  { country: "cz", year: 1958, category: "People", text: "A young scenario writer named Miloš Forman cut his teeth on the Laterna Magika spectacle in Brussels, years before he became an Oscar-winning film director." },
  { country: "cz", year: 1959, category: "Science & tech", text: "In Prague the chemist Otto Wichterle began experimentally fitting patients with the world's first soft hydrogel contact lenses, a breakthrough he would soon perfect by spin-casting them on apparatus built partly from his children's erector set." },
  { country: "cz", year: 1959, category: "Culture", text: "The triumph of Laterna Magika abroad led to the founding of a permanent multimedia theatre company in Prague in May, cementing the art form as a national cultural export." },
  { country: "cz", year: 1960, category: "Politics", text: "A new Marxist-Leninist constitution promulgated on 11 July renamed the country the Czechoslovak Socialist Republic, proudly declaring it the first state after the Soviet Union to have 'achieved socialism.'" },
  { country: "cz", year: 1960, category: "Science & tech", text: "The journal Nature published 'Hydrophilic gels for biological use' by chemists Otto Wichterle and Drahoslav Lim, laying the scientific groundwork for the soft contact lens." },
  { country: "cz", year: 1960, category: "People", text: "Future tennis world number one Ivan Lendl, who would dominate the men's game in the 1980s, was born in Ostrava on 7 March this year." },
  { country: "cz", year: 1961, category: "Science & tech", text: "On Christmas afternoon, Otto Wichterle spun the first four soft hydrogel contact lenses on a home-built apparatus assembled from his sons' Merkur construction set and a bicycle dynamo." },
  { country: "cz", year: 1961, category: "Everyday life", text: "The over-ambitious Third Five-Year Plan launched this year soon proved hopelessly unrealistic, foreshadowing shortages of consumer goods and long queues for basic products." },
  { country: "cz", year: 1962, category: "Sport", text: "The national football team reached the World Cup final in Santiago, taking an early lead through Josef Masopust before losing 3-1 to Brazil and finishing as runners-up." },
  { country: "cz", year: 1963, category: "Everyday life", text: "National income actually fell this year as planners abandoned the collapsing five-year plan in favour of annual targets, with industrial growth among the lowest in Eastern Europe." },
  { country: "cz", year: 1963, category: "Sport", text: "At the ice hockey world championships in Stockholm, the national team beat Sweden 3-2 to claim the bronze medal." },
  { country: "cz", year: 1964, category: "Everyday life", text: "The rear-engined Skoda 1000 MB, named for its home town of Mlada Boleslav, debuted in April as the country's first mass-produced car with a self-supporting body." },
  { country: "cz", year: 1964, category: "Sport", text: "At the Innsbruck Winter Olympics the ice hockey team finished with bronze, behind silver medallists Sweden and gold medallists the Soviet Union." },
  { country: "cz", year: 1965, category: "Culture", text: "The wartime drama 'The Shop on Main Street', directed by Jan Kadar and Elmar Klos, won the Academy Award for Best Foreign Language Film, the country's first Oscar." },
  { country: "cz", year: 1965, category: "Culture", text: "Czechoslovak Television aired the first episode of 'Vecernicek' on 2 January, the beloved children's bedtime series that soon adopted its enduring image of a paper-hatted boy on a rocking horse wishing viewers good evening." },
  { country: "cz", year: 1966, category: "Culture", text: "Vera Chytilova's anarchic feminist comedy 'Daisies' was banned at home, partly for its scenes of gross food waste at a time of consumer shortages, and its director was barred from filmmaking for years." },
  { country: "cz", year: 1966, category: "Everyday life", text: "Prefabricated 'panelak' housing technology advanced rapidly, with giant residential blocks of hundreds of flats rising on the edges of cities, increasingly softened with shops, schools and clinics." },
  { country: "cz", year: 1967, category: "Culture", text: "At the Fourth Writers' Congress in June, Milan Kundera, Ludvik Vaculik, Pavel Kohout and Vaclav Havel openly attacked censorship and party rule, an outburst often seen as the prelude to the Prague Spring." },
  { country: "cz", year: 1967, category: "Culture", text: "Jiri Menzel's coming-of-age film 'Closely Watched Trains', adapted from a Bohumil Hrabal novella, was released abroad and went on to win the Academy Award for Best Foreign Language Film." },
  { country: "cz", year: 1968, category: "Politics", text: "The election of reformer Alexander Dubcek as Communist Party First Secretary on 5 January launched the Prague Spring and its promise of 'socialism with a human face.'" },
  { country: "cz", year: 1968, category: "Culture", text: "Some seventy intellectuals and artists signed the 'Two Thousand Words' manifesto, drafted by the writer Ludvik Vaculik and published on 27 June, calling for deeper democratisation." },
  { country: "cz", year: 1968, category: "Upheaval", text: "On the night of 20-21 August around half a million Warsaw Pact troops with thousands of tanks invaded in Operation Danube, crushing the reforms and killing more than a hundred civilians." },
  { country: "cz", year: 1968, category: "Culture", text: "Days after the tanks rolled in, singer Marta Kubisova recorded 'Modlitba pro Martu' (A Prayer for Marta), which became an anthem of national resistance before the regime banned it and barred her from performing for two decades." },
  { country: "cz", year: 1968, category: "Sport", text: "At the Mexico City Olympics, gymnast Vera Caslavska won four golds and two silvers and pointedly turned her head down and away from the Soviet flag during the anthem in silent protest at the invasion." },
  { country: "cz", year: 1969, category: "Politics", text: "On 1 January the unitary state became a federation of the Czech Socialist Republic and the Slovak Socialist Republic, with a new bicameral Federal Assembly." },
  { country: "cz", year: 1969, category: "Upheaval", text: "On 16 January, the twenty-year-old student Jan Palach set himself alight in Wenceslas Square in protest at the occupation and died three days later; some 200,000 mourners attended his funeral." },
  { country: "cz", year: 1969, category: "Sport", text: "When the national ice hockey team twice beat the Soviet Union at the Stockholm world championships in March, jubilant crowds filled the streets and demonstrators ransacked the Soviet Aeroflot office on Wenceslas Square." },
  { country: "cz", year: 1969, category: "Everyday life", text: "By the end of the year some three million television sets were in use across the country, reflecting the medium's rapid spread through the decade." },
  { country: "cz", year: 1969, category: "People", text: "Olympic running legend Emil Zatopek, who had endorsed the Prague Spring and signed the Two Thousand Words, was stripped of his army rank, expelled from the party and sent to labour in the uranium mines at Jachymov." },
  { country: "cz", year: 1970, category: "Politics", text: "During the post-Prague-Spring purges, screening commissions expelled roughly half a million members from the Communist Party, and losing one's party card so often meant losing one's career that dismissed professors drove taxis and former diplomats clerked in hotels." },
  { country: "cz", year: 1970, category: "Politics", text: "Gustav Husak tightened his grip as party leader, replacing reformist members of the Central Committee with hardliners and steering the country firmly back into line with the Soviet bloc after the crushed reforms of 1968." },
  { country: "cz", year: 1971, category: "Politics", text: "At the officially sanctioned Fourteenth Party Congress in May, the leadership declared the process of \"normalization\" satisfactorily completed, and parliamentary elections that November duly returned the regime's single approved candidate list with the customary near-unanimous vote." },
  { country: "cz", year: 1972, category: "Sport", text: "On 15 February, in the mining town of Kladno, a future hockey legend who would become one of the most prolific point-scorers in NHL history was born." },
  { country: "cz", year: 1972, category: "Sport", text: "At the ice hockey World Championships staged in Prague in April, the home team beat the Soviet Union twice in the round robin and took gold, ending the Soviets' run of nine consecutive titles and igniting jubilation in the streets." },
  { country: "cz", year: 1972, category: "Science & tech", text: "The bold asymmetrical cable-stayed bridge over the Danube in Bratislava, crowned by a flying-saucer-shaped restaurant atop its single 85-metre pylon, officially opened on 26 August after years of construction." },
  { country: "cz", year: 1973, category: "Politics", text: "On 11 December the Treaty of Prague was signed with West Germany, declaring the 1938 Munich Agreement null and void and establishing full diplomatic relations between the two states for the first time since the Second World War." },
  { country: "cz", year: 1974, category: "Everyday life", text: "Vast prefabricated concrete housing estates were rising on the edges of cities, most ambitiously Prague's Jizni Mesto, eventually home to around 100,000 people, where families prized a new flat despite walls so thin that neighbours' televisions and arguments carried straight through." },
  { country: "cz", year: 1975, category: "Sport", text: "On 6 September, the eighteen-year-old tennis prodigy who had just lost a US Open semifinal to Chris Evert defected to the United States and sought political asylum, after which the authorities stripped her of her citizenship." },
  { country: "cz", year: 1976, category: "Sport", text: "On 20 June in Belgrade, the national football team beat West Germany in a penalty shoot-out to win the European Championship, the decisive kick an audacious chip down the centre of the goal that has been imitated ever since as the \"Panenka.\"" },
  { country: "cz", year: 1976, category: "Sport", text: "The ice hockey team won its fourth world title in Katowice, sweeping unbeaten through all nine games of the tournament." },
  { country: "cz", year: 1976, category: "Culture", text: "After a spring crackdown swept up dozens of musicians, four members of the banned underground rock band the Plastic People of the Universe were tried in September and jailed for \"organized disturbance of the peace,\" a prosecution that helped galvanise the writing of a famous human-rights manifesto." },
  { country: "cz", year: 1976, category: "Everyday life", text: "The boxy, rear-engined Skoda 105 and 120 were unveiled at the Brno engineering fair, selling for around 55,000 to 58,000 crowns to buyers who often waited years for the right to purchase a car." },
  { country: "cz", year: 1976, category: "Culture", text: "Director Vera Chytilova, banned from filmmaking since the 1968 invasion, was finally allowed back behind the camera to make The Apple Game, though she first had to write directly to President Husak appealing for the right to work." },
  { country: "cz", year: 1977, category: "Politics", text: "On 6 January the human-rights declaration Charter 77 appeared with 242 founding signatories calling on the government to honour the Helsinki Accords, and its couriers, among them Vaclav Havel, were detained while trying to deliver it to the Federal Assembly." },
  { country: "cz", year: 1977, category: "Culture", text: "In a swift state-orchestrated rebuttal, thousands of leading performers and writers gathered at the National Theatre to endorse an \"Anticharter,\" with celebrated singer Karel Gott among the names, though some later claimed they had been misled about what they signed." },
  { country: "cz", year: 1977, category: "Culture", text: "The popular serial Zena za pultem (The Woman Behind the Counter), built around the daily life of a Prague shop assistant, premiered and drew the notice of the Communist Party leadership, partly over one of its scenes." },
  { country: "cz", year: 1977, category: "People", text: "The philosopher Jan Patocka, one of Charter 77's three original spokesmen, died in March after a series of gruelling police interrogations, and his funeral became a quiet act of defiance under heavy surveillance." },
  { country: "cz", year: 1978, category: "Science & tech", text: "On 2 March a military pilot lifted off aboard Soyuz 28 to dock with the Salyut 6 station, becoming the first person in space from a country other than the Soviet Union or the United States and returning to Earth on 10 March." },
  { country: "cz", year: 1978, category: "Culture", text: "The hospital drama Nemocnice na kraji mesta (Hospital at the End of the City) began broadcasting and became a beloved national institution, its ensemble of doctors followed by millions of families gathered around the television." },
  { country: "cz", year: 1978, category: "Everyday life", text: "For scarce Western goods such as denim jeans, foreign electronics and quality coffee, citizens turned to the state's Tuzex hard-currency shops, whose special vouchers were traded on a thriving black market by hustlers known as \"vekslaci.\"" },
  { country: "cz", year: 1979, category: "Upheaval", text: "In October six members of the Committee for the Defence of the Unjustly Prosecuted were tried for subversion, with the playwright Vaclav Havel sentenced to four and a half years in prison." },
  { country: "cz", year: 1979, category: "Everyday life", text: "Across the decade the regime traded consumer comforts for political quiet, and the prefab estate flat, the family Skoda, and the weekend chata cottage where many escaped to garden became the modest horizons of ordinary life." },
  { country: "cz", year: 1980, category: "Sport", text: "Ivan Lendl, unbeaten across seven singles and three doubles matches, anchored the national team to its first Davis Cup title with a 4-1 victory over Italy before a roaring home crowd in Prague." },
  { country: "cz", year: 1980, category: "Sport", text: "At the Lake Placid Winter Olympics the heavily favored ice hockey team was stunned 7-3 by an underdog United States squad that would go on to its famous 'Miracle on Ice'." },
  { country: "cz", year: 1980, category: "Everyday life", text: "Ordinary families endured waiting lists of several years for a domestically built Skoda, then handed over years of savings for a boxy little sedan when their turn finally came." },
  { country: "cz", year: 1981, category: "Politics", text: "Gustav Husak's regime entered the new decade enforcing rigid 'normalization,' demanding conformity in public life while trying to buy acquiescence with a modestly improved standard of living." },
  { country: "cz", year: 1981, category: "Everyday life", text: "Shortages were a fact of daily life, with citizens routinely queuing for hours and improvising through black markets to obtain everything from sugar to spare parts." },
  { country: "cz", year: 1982, category: "Sport", text: "At the world ice hockey championship in Finland in February, the national team took silver after losing the decisive game 5-3 to a Soviet side that claimed its second straight world title." },
  { country: "cz", year: 1982, category: "Sport", text: "Ostrava-born Ivan Lendl bestrode men's tennis, winning fifteen of the twenty-three tournaments he entered and reeling off 44 consecutive match victories, the third-longest streak of the open era, before beating John McEnroe to take the season-ending WCT Finals in Dallas." },
  { country: "cz", year: 1983, category: "Culture", text: "An article in the Communist weekly Tribuna, 'New Wave with Old Content,' denounced rock as a corrupting influence on youth and launched a crackdown that soon stripped popular bands of their performing licenses." },
  { country: "cz", year: 1983, category: "Culture", text: "The acclaimed new-wave band Prazsky vyber lost its performance license and was effectively banned, a casualty of an official campaign portraying rock music as a path to passivity and antisocial behavior." },
  { country: "cz", year: 1983, category: "Everyday life", text: "Citizens with hard currency or specially bought vouchers shopped at Tuzex stores for coveted Western goods, above all blue jeans, that were unobtainable in ordinary shops." },
  { country: "cz", year: 1984, category: "Sport", text: "The national ice hockey team took silver at the Sarajevo Winter Olympics, shut out by the Soviet Union in the decisive game of the tournament." },
  { country: "cz", year: 1984, category: "Culture", text: "Karel Gott, the silky-voiced crooner dubbed the 'Golden Voice of Prague,' reigned as the country's most popular singer, his stardom embraced by a regime whose Anti-Charter petition he had signed." },
  { country: "cz", year: 1985, category: "Sport", text: "Before a jubilant home crowd in Prague, the national ice hockey team beat Canada 5-3 to clinch its sixth world championship, relegating the favored Soviets to bronze." },
  { country: "cz", year: 1985, category: "Culture", text: "Jiri Menzel's tender comedy 'My Sweet Little Village,' following the gentle, troubled Otik in a close-knit rural community, became a beloved hit and would earn an Academy Award nomination." },
  { country: "cz", year: 1985, category: "Everyday life", text: "Tens of thousands of synchronized performers filled the vast Strahov Stadium for the quinquennial Spartakiad mass gymnastics display, which launched the enduringly catchy pop anthem 'Poupata.'" },
  { country: "cz", year: 1985, category: "Politics", text: "Well over a hundred thousand Catholics defied the regime at a pilgrimage to Velehrad marking the 1,100th anniversary of St. Methodius's death, booing officials and turning the religious gathering into a bold protest." },
  { country: "cz", year: 1986, category: "Upheaval", text: "After the Chernobyl disaster the authorities suppressed information and went ahead with the traditional May Day celebrations, leaving people to sunbathe and march outdoors while radioactive fallout drifted overhead." },
  { country: "cz", year: 1986, category: "Culture", text: "Police arrested Karel Srp, head of the independent Jazz Section, who was later jailed for sixteen months, punishing an organization whose smuggled books and records had reached thousands of readers." },
  { country: "cz", year: 1986, category: "Sport", text: "Exiled stars Ivan Lendl and Martina Navratilova dominated world tennis as the men's and women's number one players, though the regime treated the defected Navratilova as a non-person at home." },
  { country: "cz", year: 1987, category: "Politics", text: "The seventy-four-year-old Gustav Husak stepped down as Communist Party chief in favor of conservative Milos Jakes, while clinging to the largely ceremonial post of president." },
  { country: "cz", year: 1987, category: "Science & tech", text: "Decades of burning sulfurous brown coal had made northern Bohemia part of Europe's 'Black Triangle,' where acid rain killed swaths of forest and locals suffered respiratory illness at twice the national rate." },
  { country: "cz", year: 1988, category: "Upheaval", text: "In Bratislava thousands of Catholics held a silent, candle-lit demonstration for religious freedom that riot police broke up with water cannon, a rare open challenge to the regime." },
  { country: "cz", year: 1989, category: "Upheaval", text: "During 'Palach Week' in January, marking twenty years since Jan Palach's self-immolation, riot police battled demonstrators and arrested hundreds, among them the dissident playwright Vaclav Havel." },
  { country: "cz", year: 1989, category: "Upheaval", text: "On 17 November riot police violently broke up a student march commemorating a 1939 Nazi crackdown, igniting the peaceful Velvet Revolution that within weeks toppled the Communist regime." },
  { country: "cz", year: 1989, category: "Politics", text: "Half a million people packed Prague's streets and a nationwide general strike on 27 November helped force the Communist Party to surrender its constitutional monopoly on power." },
  { country: "cz", year: 1989, category: "People", text: "On 29 December the Federal Assembly elected the once-imprisoned dissident playwright Vaclav Havel as president, capping a year that had begun with him behind bars." },
  { country: "cz", year: 1990, category: "Politics", text: "On 8 and 9 June voters went to the polls in the first free elections in 44 years, with turnout reaching an extraordinary 96.2 percent and the Civic Forum movement winning a sweeping victory." },
  { country: "cz", year: 1990, category: "Culture", text: "On 18 August the Rolling Stones played to more than 100,000 fans at Prague's vast Strahov Stadium under the slogan 'Tanks are rolling out, the Stones are rolling in.'" },
  { country: "cz", year: 1990, category: "Politics", text: "On 5 July the former dissident playwright Vaclav Havel was re-elected president by the Federal Assembly, cementing his journey from prison cell to presidential office." },
  { country: "cz", year: 1990, category: "People", text: "The future two-time Wimbledon champion and world No. 2 tennis player Petra Kvitova was born on 8 March in the town of Bilovec." },
  { country: "cz", year: 1990, category: "Culture", text: "The rock band Lucie, fronted by Robert Kodym, released its debut album and went on to become one of the era's most popular groups, with hits like 'Medvidek' and 'Amerika' defining the soundtrack of the post-revolution decade." },
  { country: "cz", year: 1991, category: "Upheaval", text: "On 27 June the last Soviet soldier left, ending a military occupation that had begun with the 1968 Warsaw Pact invasion and had stationed tens of thousands of troops for 23 years." },
  { country: "cz", year: 1991, category: "Politics", text: "On 4 October parliament passed the lustration law, barring former secret-police collaborators and high communist officials from a wide range of public posts." },
  { country: "cz", year: 1991, category: "Everyday life", text: "On 28 March the government and Volkswagen signed the deal making the German giant Skoda's strategic partner, beginning the transformation of the maker of the boxy Favorit into a global brand." },
  { country: "cz", year: 1992, category: "Everyday life", text: "On 20 March the first McDonald's opened on Prague's Vodickova Street, drawing an estimated 11,000 people who queued for their first taste of an American hamburger." },
  { country: "cz", year: 1992, category: "Politics", text: "Under finance minister and later prime minister Vaclav Klaus, citizens used books of vouchers to buy shares in state enterprises in a mass coupon-privatization scheme that handed the public ownership of the formerly socialist economy." },
  { country: "cz", year: 1992, category: "Politics", text: "On 25 November the Federal Assembly passed the constitutional act agreeing to split the country into two states at the end of the year, sealing the so-called Velvet Divorce." },
  { country: "cz", year: 1992, category: "Politics", text: "On 16 December the Czech National Council adopted the new constitution of the soon-to-be-independent republic, set to take effect on the first day of 1993." },
  { country: "cz", year: 1993, category: "Politics", text: "On 1 January the country split peacefully into two new states, with the independent Czech Republic and Slovakia simultaneously coming into being in the only entirely bloodless breakup in the former Eastern Bloc." },
  { country: "cz", year: 1993, category: "Politics", text: "On 26 January Vaclav Havel was elected the first president of the newly independent republic, winning 109 votes in the first round and taking office on 2 February." },
  { country: "cz", year: 1993, category: "Everyday life", text: "On 8 February the shared federal currency was divided, the first new money being old banknotes bearing glued-on adhesive stamps marked with their denomination until freshly designed notes could be printed." },
  { country: "cz", year: 1994, category: "Culture", text: "On 4 February TV Nova went on the air as the first nationwide private commercial television station in the entire former Eastern Bloc, swiftly capturing the largest audience in the country." },
  { country: "cz", year: 1995, category: "Politics", text: "On 21 December the country became the first ex-communist state to join the OECD, a milestone in its reintegration with Western economies." },
  { country: "cz", year: 1996, category: "Sport", text: "On 25 May Jan Zelezny hurled the javelin 98.48 metres in Jena, Germany, setting a world record that would still stand decades later as one of athletics' most untouchable marks." },
  { country: "cz", year: 1996, category: "Sport", text: "On 30 June the national football team lost the European Championship final 2-1 to Germany at Wembley, beaten by Oliver Bierhoff's golden goal in extra time after Patrik Berger had given them the lead from the penalty spot." },
  { country: "cz", year: 1996, category: "Sport", text: "At the Atlanta Summer Games Jan Zelezny successfully defended his Olympic javelin title, claiming the second of his three consecutive Olympic golds." },
  { country: "cz", year: 1997, category: "Upheaval", text: "In early July catastrophic rains triggered the so-called 'Flood of the Century' across Moravia and Silesia, killing nearly 60 people, leaving over ten thousand homeless, and inundating the historic centre of Olomouc." },
  { country: "cz", year: 1997, category: "Culture", text: "On 24 March the film Kolya, directed by Jan Sverak and starring his father Zdenek Sverak as a Prague cellist who unexpectedly raises a small Russian boy, won the Academy Award for Best Foreign Language Film." },
  { country: "cz", year: 1998, category: "Sport", text: "On 22 February the national ice hockey team beat Russia 1-0 in the Nagano Olympic final, with goaltender Dominik Hasek nearly impassable and Petr Svoboda scoring the only goal to claim the country's first hockey gold." },
  { country: "cz", year: 1998, category: "Sport", text: "At the age of 29 Jana Novotna won the Wimbledon women's singles title, defeating Nathalie Tauziat in the final to become the oldest first-time Grand Slam champion of the Open era." },
  { country: "cz", year: 1999, category: "Politics", text: "On 12 March the country formally joined NATO alongside Poland and Hungary, depositing its instrument of accession in Independence, Missouri, in a move confirming the definitive end of the Cold War in Central Europe." },
  { country: "cz", year: 2000, category: "Science & tech", text: "Volkswagen completed its takeover of the famed carmaker headquartered in Mladá Boleslav, buying out the government's remaining stake to make the maker of the Octavia and Fabia a wholly owned subsidiary of the German group." },
  { country: "cz", year: 2000, category: "Culture", text: "Jan Hřebejk's wartime drama 'Divided We Fall' (Musíme si pomáhat), about a childless couple hiding a Jewish neighbour from the Nazis, premiered and went on to earn an Academy Award nomination for Best Foreign Language Film." },
  { country: "cz", year: 2001, category: "Sport", text: "In Götzis, Austria, decathlete Roman Šebrle became the first athlete in history to break the 9,000-point barrier, scoring a world-record 9,026 points across the ten events." },
  { country: "cz", year: 2001, category: "Science & tech", text: "The antiviral drug Viread, built on the compound tenofovir devised by chemist Antonín Holý at Prague's Institute of Organic Chemistry and Biochemistry, won U.S. approval to treat HIV/AIDS and would eventually help millions worldwide." },
  { country: "cz", year: 2002, category: "Upheaval", text: "A catastrophic 'five-hundred-year' flood swept down the Vltava in mid-August, the worst in the nation's recorded history, inundating the Prague districts of Karlín, Holešovice and Malá Strana, killing 17 people and forcing some 40,000 from their homes." },
  { country: "cz", year: 2002, category: "Everyday life", text: "When floodwaters drowned 134 animals at Prague Zoo, a fur seal named Gaston escaped and swam down the Vltava and Elbe all the way to Dresden in Germany, where he died of exhaustion, becoming a poignant symbol of the disaster and later honoured with a statue." },
  { country: "cz", year: 2002, category: "Politics", text: "Prague hosted the first NATO summit ever held in a former Warsaw Pact country, where the alliance invited seven new members, including neighbouring Slovakia, to begin accession talks." },
  { country: "cz", year: 2003, category: "Politics", text: "Václav Havel left Prague Castle as his second presidential term ended, and after three rounds of fractious balloting his old rival, the economist Václav Klaus, was elected to succeed him by a margin of just one vote." },
  { country: "cz", year: 2003, category: "Sport", text: "Juventus midfielder Pavel Nedvěd was awarded the Ballon d'Or as Europe's footballer of the year, becoming only the second player from his country to win the prize after Josef Masopust in 1962." },
  { country: "cz", year: 2004, category: "Politics", text: "On 1 May the country formally joined the European Union as part of the historic 'big bang' enlargement that admitted ten new member states at once." },
  { country: "cz", year: 2004, category: "Culture", text: "Seventeen-year-old Aneta Langerová won the first season of the talent show 'Česko hledá SuperStar', the local version of Pop Idol, taking a 79 percent share of the final vote and launching a pop career." },
  { country: "cz", year: 2004, category: "Sport", text: "Goalkeeper Petr Čech signed for Chelsea after the national football team's run to the Euro 2004 semi-finals, and he went on to anchor a record-setting Premier League defence with 24 clean sheets in his first season." },
  { country: "cz", year: 2005, category: "Sport", text: "Backed by a shutout from goaltender Tomáš Vokoun, the national ice hockey team beat Canada 3-0 in the Vienna final to win the World Championship, in a tournament where the NHL lockout freed every star to play." },
  { country: "cz", year: 2005, category: "Culture", text: "In a televised 'Greatest Czech' poll, the fictional polymath Jára Cimrman topped the public vote but was disqualified for not being a real person, leaving the medieval king and emperor Charles IV as the official winner." },
  { country: "cz", year: 2005, category: "Everyday life", text: "Beer consumption reached a national peak of 163.5 litres per person a year, the highest in the world, as a nation of devoted drinkers put away brews like Pilsner Urquell and Gambrinus." },
  { country: "cz", year: 2006, category: "Politics", text: "June's parliamentary election produced a paralysing deadlock, with the centre-right and left-wing blocs each holding exactly 100 of the 200 seats, leaving the country without a functioning government for months." },
  { country: "cz", year: 2007, category: "Politics", text: "The United States opened negotiations to build a missile-defence radar at the Brdy military range between Prague and Pilsen, a plan that drew sustained public protest and local referendums overwhelmingly against it." },
  { country: "cz", year: 2007, category: "Everyday life", text: "On 21 December the country entered the Schengen zone, and overnight the checkpoints along its land borders with Germany, Austria, Poland and Slovakia were abolished, letting people cross freely for the first time in generations." },
  { country: "cz", year: 2008, category: "Politics", text: "President Václav Klaus was re-elected by parliament to a second five-year term in February, again by a single vote, after another round of bitterly contested balloting." },
  { country: "cz", year: 2009, category: "Politics", text: "The country held the rotating presidency of the European Union for the first time, only for the centre-right government of Mirek Topolánek to collapse mid-term after losing a no-confidence vote, with statistician Jan Fischer installed to lead a caretaker cabinet." },
  { country: "cz", year: 2009, category: "Culture", text: "Artist David Černý unveiled 'Entropa' at the EU Council building in Brussels, a giant mosaic mocking national stereotypes that turned out to be a hoax he and his assistants had made themselves rather than the work of artists from all 27 member states, sparking a diplomatic furore." },
  { country: "cz", year: 2009, category: "Politics", text: "In September the Obama administration scrapped the planned Brdy missile-defence radar after revising its assessment of the Iranian threat, ending one of the most divisive foreign-policy disputes of the decade." },
  { country: "cz", year: 2009, category: "Everyday life", text: "The final stretch of motorway linking Ostrava to the national highway network was opened as part of the D1, capping a decade of heavy state and EU-funded investment in the country's expanding road network." },
  { country: "cz", year: 2010, category: "Sport", text: "The national ice hockey team, captained by the veteran star Jaromir Jagr, won gold at the World Championship in Germany, beating Russia 2-1 in the final." },
  { country: "cz", year: 2010, category: "Politics", text: "After parliamentary elections in late May, the Social Democrats won the most votes yet a coalition of three centre-right parties took power under Prime Minister Petr Necas, who imposed a programme of crisis-era austerity." },
  { country: "cz", year: 2011, category: "Sport", text: "The left-handed power-hitter Petra Kvitova, then only 21, won her first Wimbledon singles title by beating Maria Sharapova, capping a breakthrough year that took her to the top of the women's game." },
  { country: "cz", year: 2011, category: "Sport", text: "Led by Kvitova, the women's tennis team beat Russia in Moscow to capture the country's first Fed Cup title as an independent nation." },
  { country: "cz", year: 2011, category: "People", text: "Vaclav Havel, the dissident playwright who became the last president of Czechoslovakia and the first of the post-communist republic, died at his country house in Hradecek on 18 December at the age of 75." },
  { country: "cz", year: 2011, category: "Culture", text: "Havel's state funeral was held in the Gothic St. Vitus Cathedral within Prague Castle, drawing mourners and dignitaries from more than thirty countries including Bill and Hillary Clinton." },
  { country: "cz", year: 2012, category: "Upheaval", text: "A wave of methanol poisonings from bootleg spirits cut with industrial alcohol killed dozens of people, prompting a temporary nationwide ban on the sale of all spirits above 20 percent in what locals called the 'methanol prohibition'." },
  { country: "cz", year: 2012, category: "Politics", text: "Parliament approved a constitutional amendment introducing direct popular election of the president, ending two decades in which the head of state had been chosen by a joint session of parliament." },
  { country: "cz", year: 2013, category: "Politics", text: "In the first-ever direct presidential election, former prime minister Milos Zeman defeated Foreign Minister Karel Schwarzenberg in a January runoff, winning about 55 percent of the vote." },
  { country: "cz", year: 2013, category: "Politics", text: "Outgoing President Vaclav Klaus marked the republic's twentieth anniversary with a sweeping New Year amnesty that quashed several long-running corruption trials, sparking petitions and public outrage." },
  { country: "cz", year: 2013, category: "Upheaval", text: "Heavy June rains swelled the Vltava and other rivers, forcing the government to declare a state of emergency across seven regions, close central Prague's metro stations and evacuate more than 19,000 people." },
  { country: "cz", year: 2013, category: "Politics", text: "Prime Minister Petr Necas resigned in June after his chief of staff and intimate Jana Nagyova was arrested for abuse of power, a scandal involving the secret surveillance of his wife that toppled the whole cabinet." },
  { country: "cz", year: 2013, category: "Everyday life", text: "Facing recession and the threat of deflation, the central bank began intervening in foreign-exchange markets in November to weaken the koruna, pledging to keep it from strengthening below 27 to the euro." },
  { country: "cz", year: 2014, category: "Politics", text: "Social Democrat Bohuslav Sobotka was sworn in as prime minister at the head of a coalition in which the billionaire Andrej Babis and his new ANO movement took the finance ministry." },
  { country: "cz", year: 2014, category: "Sport", text: "At the Sochi Winter Olympics, the 20-year-old Eva Samkova, racing with a painted moustache for luck, stormed to gold in the women's snowboard cross." },
  { country: "cz", year: 2014, category: "Sport", text: "Speed skater Martina Sablikova successfully defended her Olympic title in the 5,000 metres at Sochi, adding a silver in the 3,000 metres." },
  { country: "cz", year: 2014, category: "Upheaval", text: "Two huge explosions destroyed ammunition depots at Vrbetice in the southeast, killing two men, in blasts later attributed by Czech authorities to officers of Russian military intelligence." },
  { country: "cz", year: 2014, category: "Sport", text: "Petra Kvitova won her second Wimbledon singles title, demolishing Canada's Eugenie Bouchard 6-3, 6-0 in a final that lasted under an hour." },
  { country: "cz", year: 2015, category: "Politics", text: "The government joined Hungary, Slovakia and Romania in voting against the EU's plan to relocate refugees by quota, and President Zeman denounced the migration wave as an 'organised invasion' in his Christmas message." },
  { country: "cz", year: 2016, category: "Politics", text: "The cabinet approved 'Czechia' as the official short-form English name of the country, which was duly entered into the United Nations databases of country names that July." },
  { country: "cz", year: 2016, category: "Everyday life", text: "The finance ministry under Andrej Babis rolled out the EET electronic sales-registration system, starting with restaurants, hotels and cafes, which had to wire each receipt to the tax authority in real time." },
  { country: "cz", year: 2017, category: "Everyday life", text: "A long-debated indoor smoking ban took effect on 31 May, finally clearing the haze from the country's beloved pubs, restaurants and bars." },
  { country: "cz", year: 2017, category: "Sport", text: "The climber Adam Ondra made the first ascent of a 45-metre route at Flatanger in Norway, naming it 'Silence' and proposing the grade 9c, making it the hardest sport climb in the world." },
  { country: "cz", year: 2017, category: "Politics", text: "Andrej Babis's ANO movement won nearly a third of the vote in October's parliamentary election, and in December he became the wealthiest person ever to be appointed prime minister." },
  { country: "cz", year: 2018, category: "Sport", text: "At the Pyeongchang Winter Olympics, Ester Ledecka stunned the sporting world by winning the alpine super-G by one hundredth of a second and then a second gold in parallel giant slalom snowboarding, the first athlete ever to take golds on skis and a snowboard at the same Games." },
  { country: "cz", year: 2018, category: "Politics", text: "President Milos Zeman, running on an anti-immigrant platform, narrowly won a second five-year term in January's runoff, beating the former Academy of Sciences chief Jiri Drahos with about 51 percent." },
  { country: "cz", year: 2018, category: "Science & tech", text: "The ELI Beamlines facility at Dolni Brezany near Prague, home to some of the world's most powerful lasers, opened to external researchers." },
  { country: "cz", year: 2019, category: "Upheaval", text: "In June a quarter of a million people packed Prague's Letna plain at a rally organised by the 'Million Moments for Democracy' movement to demand the resignation of Prime Minister Babis, the largest demonstration since the 1989 Velvet Revolution." },
  { country: "cz", year: 2019, category: "Everyday life", text: "The country again topped the world in beer consumption, with citizens drinking well over 130 litres per person a year from breweries such as Pilsner Urquell, Staropramen and Budweiser Budvar." },
  { country: "cz", year: 2020, category: "Everyday life", text: "On 19 March it became the first European country to make wearing face masks compulsory in public, and within weeks home sewing machines were humming as citizens stitched cloth masks for neighbours and hospitals." },
  { country: "cz", year: 2020, category: "Upheaval", text: "The first three COVID-19 cases were confirmed on 1 March, and by 12 March the government had declared a 30-day state of emergency, soon sealing the borders to foreigners." },
  { country: "cz", year: 2020, category: "Politics", text: "In October's regional elections, Prime Minister Andrej Babis's ANO movement triumphed in ten of the thirteen regions, with voters casting their ballots in face masks." },
  { country: "cz", year: 2021, category: "Upheaval", text: "On the evening of 24 June a rare F4 tornado up to 3.5 kilometres wide tore through villages in South Moravia, killing six people, injuring nearly 600, and flattening swathes of Hrusky and Moravska Nova Ves." },
  { country: "cz", year: 2021, category: "Sport", text: "Barbora Krejcikova lifted the singles trophy at the French Open and went on to win Olympic doubles gold in Tokyo that same year." },
  { country: "cz", year: 2021, category: "Politics", text: "The centre-right Spolu alliance edged out Babis's ANO by less than a percentage point in the closest parliamentary election in the country's history, with the old Communist and Social Democratic parties failing for the first time to win a single seat." },
  { country: "cz", year: 2021, category: "Science & tech", text: "Cybersecurity firm Avast, headquartered in Prague, agreed in August to a multi-billion-dollar merger with America's NortonLifeLock, creating one of the world's largest consumer-security companies." },
  { country: "cz", year: 2022, category: "Sport", text: "At the Beijing Winter Olympics, Ester Ledecka defended her snowboard parallel giant slalom title to claim the nation's first gold of the Games and her third career Olympic gold." },
  { country: "cz", year: 2022, category: "Upheaval", text: "Following Russia's invasion of Ukraine, the country took in over 300,000 refugees within a month and ended the year hosting the highest number of displaced Ukrainians per capita in the EU." },
  { country: "cz", year: 2022, category: "Everyday life", text: "As inflation surged toward 18 percent and energy bills bit hard, around 70,000 people rallied on Prague's Wenceslas Square on 3 September to protest the cost-of-living crisis." },
  { country: "cz", year: 2022, category: "Politics", text: "The country held the rotating presidency of the Council of the European Union in the second half of the year, steering EU policy as it scrambled to respond to war and the energy shock." },
  { country: "cz", year: 2023, category: "Politics", text: "Retired NATO general Petr Pavel won the presidential runoff against Andrej Babis with 58 percent of the vote, taking office on 9 March on a firmly pro-Western, pro-Ukrainian platform." },
  { country: "cz", year: 2023, category: "Sport", text: "Marketa Vondrousova became the first unseeded woman ever to win the Wimbledon singles title, beating Ons Jabeur in the final." },
  { country: "cz", year: 2023, category: "Upheaval", text: "On 21 December a postgraduate student opened fire at Charles University's Faculty of Arts in central Prague, killing 14 people in what the president called the most tragic incident in the nation's history." },
  { country: "cz", year: 2023, category: "People", text: "Karel Schwarzenberg, the cigar-smoking nobleman and former foreign minister who helped steer the country's integration into the West, died at the age of 85 in a Vienna clinic." },
  { country: "cz", year: 2023, category: "Everyday life", text: "On 1 January the country and neighbouring Slovakia marked thirty years since the peaceful 'Velvet Divorce' that split Czechoslovakia into two independent states." },
  { country: "cz", year: 2024, category: "Sport", text: "Roared on by a sell-out Prague crowd, the national ice-hockey team beat Switzerland 2-0 in the world championship final, with David Pastrnak scoring the winner to claim a first world title on home ice since 2010." },
  { country: "cz", year: 2024, category: "Upheaval", text: "In mid-September Storm Boris dumped over 500 millimetres of rain on the Jesenik mountains, triggering floods that killed five people, forced more than 13,000 from their homes, and devastated towns like Opava and Ostrava." },
  { country: "cz", year: 2024, category: "Politics", text: "Spearheaded by President Pavel, the Czech-led ammunition initiative delivered some 1.5 million artillery shells to Ukraine, sourcing rounds from outside Europe at a moment when other Western aid was faltering." },
  { country: "cz", year: 2024, category: "Everyday life", text: "The average gross monthly wage reached roughly 46,000 crowns, yet a typical older 70-square-metre Prague flat now approached 10 million crowns, putting home ownership in the capital out of reach for many." },
  { country: "cz", year: 2024, category: "Sport", text: "Barbora Krejcikova won her second Grand Slam singles title, beating Jasmine Paolini in the Wimbledon final to become the fourth Czech woman to claim the trophy." },
  { country: "cz", year: 2024, category: "Culture", text: "Veteran screen actor Ivan Trojan received the President's Award for outstanding contribution to Czech cinema at the 58th Karlovy Vary International Film Festival." },
  { country: "cz", year: 2025, category: "Politics", text: "Andrej Babis and his ANO movement swept back to power in the October parliamentary election with 34.5 percent of the vote, and Prime Minister Petr Fiala conceded after a single term." },
  { country: "cz", year: 2025, category: "Everyday life", text: "The country retained its koruna and its title as the world's heaviest beer-drinking nation, even as the new government quietly shelved any timetable for adopting the euro." },
  { country: "cz", year: 2026, category: "Politics", text: "The Babis-led government moved to scrap the annual report assessing readiness to join the eurozone, signalling that euro adoption was off the agenda for the foreseeable future." },
  { country: "ua", year: 1930, category: "Culture", text: "Alexander Dovzhenko released his silent masterpiece Earth, a lyrical hymn to soil and village life that censors banned within days yet film historians would later rank among the greatest movies ever made." },
  { country: "ua", year: 1930, category: "Politics", text: "Stalin's forced collectivization tore through the countryside as Communist agitators herded peasants into collective farms and branded those who resisted as 'kulaks' to be liquidated as a class." },
  { country: "ua", year: 1930, category: "Upheaval", text: "In Polish-ruled Eastern Galicia the authorities unleashed a 'Pacification' campaign of mass arrests, beatings and property destruction against the ethnic population in answer to a wave of nationalist sabotage." },
  { country: "ua", year: 1930, category: "People", text: "Lina Kostenko, who would become one of the nation's most revered literary voices and a leading figure of the 'Sixtiers', was born on 19 March." },
  { country: "ua", year: 1931, category: "People", text: "The most distinguished national historian, Mykhailo Hrushevsky, author of the monumental ten-volume History of Ukraine-Rus', was exiled to Moscow under constant secret-police surveillance." },
  { country: "ua", year: 1932, category: "Science & tech", text: "The vast Dnieper Hydroelectric Station at Zaporizhzhia, the largest power plant in Europe at the time, began generating electricity from behind its 760-metre dam across the great river." },
  { country: "ua", year: 1932, category: "Politics", text: "The notorious 'Law of Spikelets' of 7 August made gleaning even a handful of ears of grain from a collective field a crime of stealing socialist property, punishable by shooting or ten years in the camps." },
  { country: "ua", year: 1932, category: "Everyday life", text: "As the internal-passport decree of December tied peasants to the countryside, starving families could trade only at state-run Torgsin shops, surrendering wedding rings and gold heirlooms for a little flour or bread." },
  { country: "ua", year: 1932, category: "Upheaval", text: "Whole villages that failed to meet impossible grain quotas were placed on 'black boards', cordoned off by the secret police, denied all trade and goods, and left to starve as a deliberate punishment." },
  { country: "ua", year: 1933, category: "Upheaval", text: "The man-made famine known as the Holodomor reached its murderous peak in the spring, when most of the roughly 3.9 million famine deaths occurred and reports of cannibalism emerged from the emptied countryside." },
  { country: "ua", year: 1933, category: "People", text: "In despairing protest at the destruction of his nation and the arrest of a close fellow writer, the modernist author Mykola Khvylovy shot himself in his Kharkiv apartment on 13 May." },
  { country: "ua", year: 1933, category: "Culture", text: "The cultural flowering of the 1920s curdled into the 'Executed Renaissance' as the party reversed Ukrainization and turned its machinery of repression on the country's writers, scholars and artists." },
  { country: "ua", year: 1933, category: "People", text: "Mykola Skrypnyk, the Bolshevik commissar who had championed the Ukrainization of schools and government, took his own life rather than recant his policies as Stalin's men dismantled them." },
  { country: "ua", year: 1934, category: "Politics", text: "In June the capital of the republic was moved from Kharkiv to the ancient city of Kyiv on the Dnieper, restoring the historic centre to its role as seat of government." },
  { country: "ua", year: 1934, category: "Science & tech", text: "The world's first specialized welding research centre, the Electric Welding Institute led by engineer Yevhen Paton, was formally established in Kyiv and would go on to pioneer automatic submerged-arc welding." },
  { country: "ua", year: 1934, category: "People", text: "Mykhailo Hrushevsky died at the age of 68 in the Caucasus spa town of Kislovodsk, soon after a routine operation, his final years dogged by persecution." },
  { country: "ua", year: 1935, category: "Everyday life", text: "On the night of 31 August the Donbas coal miner Alexei Stakhanov hewed 102 tonnes of coal in a single shift, fourteen times his quota, launching the Stakhanovite movement of record-breaking shock workers." },
  { country: "ua", year: 1936, category: "Sport", text: "Dynamo Kyiv took part in the very first Soviet football championship and finished runner-up to Spartak Moscow, beginning a top-flight life from which the club would never be relegated." },
  { country: "ua", year: 1936, category: "Sport", text: "As physical culture was centralized under a new All-Union committee, the first state-run sports schools for children opened, channelling the young toward officially organized athletics." },
  { country: "ua", year: 1937, category: "Politics", text: "In late January the republic adopted a new constitution modelled on Stalin's 1936 charter, promising direct, equal and secret elections to the soviets even as the Great Terror raged." },
  { country: "ua", year: 1937, category: "Culture", text: "Over four days in late October and early November the NKVD shot hundreds of the nation's leading minds at the Sandarmokh killing field in Karelia, among them theatre visionary Les Kurbas and playwright Mykola Kulish." },
  { country: "ua", year: 1937, category: "Everyday life", text: "The Soviet census recorded a population so diminished by famine and repression that its results were suppressed and its organizers themselves arrested for producing 'wrecking' figures." },
  { country: "ua", year: 1938, category: "Politics", text: "Voters went to the polls in the first election to the new Supreme Soviet of the republic, a single-candidate ritual that confirmed the party's grip at the height of the purges." },
  { country: "ua", year: 1939, category: "Upheaval", text: "Following the Molotov-Ribbentrop Pact, Soviet forces seized eastern Galicia and Volhynia from Poland in September, uniting the western lands with the Soviet republic and bringing Lviv under Soviet rule." },
  { country: "ua", year: 1939, category: "People", text: "The celebrated soprano Solomiya Krushelnytska, the diva credited with rescuing Puccini's Madama Butterfly, returned from Italy to her home in Lviv just weeks before the Soviets arrived." },
  { country: "ua", year: 1939, category: "Everyday life", text: "In Kyiv the Jewish community numbered some 224,000 people, more than a quarter of the city's inhabitants, sustaining Yiddish schools, a theatre and a vibrant literary life." },
  { country: "ua", year: 1940, category: "Politics", text: "Following the previous autumn's Soviet seizure of eastern Poland, millions of Poles, Ukrainians and Jews in newly annexed Galicia and Volhynia found themselves citizens of an expanded Soviet republic, their farms collectivized and their elites marked for deportation to Siberia." },
  { country: "ua", year: 1940, category: "Politics", text: "In late June the Red Army marched into Northern Bukovina and the Hertsa region after an ultimatum to Romania, and the city of Chernivtsi with its surrounding lands was folded into the Soviet republic that August." },
  { country: "ua", year: 1940, category: "People", text: "Ivan Kozhedub, a young flying enthusiast from a village in the Sumy region, was beginning the aviation training that would make him the highest-scoring Allied fighter ace of the entire Second World War with 62 confirmed kills." },
  { country: "ua", year: 1941, category: "Upheaval", text: "On the evening of 18 August retreating NKVD troops dynamited the great Dnieper hydroelectric dam at Zaporizhzhia, and the unleashed flood drowned tens of thousands of civilians and Soviet soldiers downstream." },
  { country: "ua", year: 1941, category: "Upheaval", text: "German forces entered the capital on 19 September, and ten days later, on 29-30 September, nearly 34,000 Jews were marched to the Babyn Yar ravine and shot in what became one of the largest single massacres of the Holocaust." },
  { country: "ua", year: 1941, category: "Politics", text: "As the front rolled east, the long Axis siege of the Black Sea fortress of Sevastopol began on 30 October, while the port of Odesa endured a 73-day defense before its evacuation." },
  { country: "ua", year: 1941, category: "Science & tech", text: "Yevhen Paton's welding institute, evacuated to the Urals, perfected automatic submerged-arc welding of armor plate, a breakthrough that let Soviet factories weld the hulls of T-34 tanks far faster than the enemy could." },
  { country: "ua", year: 1942, category: "Sport", text: "On 9 August, in occupied Kyiv, a team of former Dynamo and Lokomotiv footballers playing as FC Start beat a German military side 5-3 in a match later mythologized as the heroic 'Death Match.'" },
  { country: "ua", year: 1942, category: "Politics", text: "Ukrainian nationalists of the OUN-Bandera faction formed the Ukrainian Insurgent Army (UPA) in Volhynia, beginning a guerrilla campaign that would fight Germans and Soviets alike for years." },
  { country: "ua", year: 1942, category: "Upheaval", text: "Sevastopol fell to Erich von Manstein's forces on 4 July after an eight-month siege so destructive that the Soviet defenders suffered around 200,000 casualties, including some 95,000 taken prisoner in the final collapse." },
  { country: "ua", year: 1943, category: "Upheaval", text: "After the vast battle for the Dnieper, the Red Army under General Nikolai Vatutin recaptured the capital in the early hours of 6 November, finding much of the riverfront blown up by the retreating Germans after 778 days of occupation." },
  { country: "ua", year: 1943, category: "People", text: "Roman Shukhevych took command of the Ukrainian Insurgent Army in the late summer, becoming the elusive leader of an underground resistance that the Soviets would hunt for the rest of the decade." },
  { country: "ua", year: 1943, category: "Culture", text: "The celebrated film director Oleksandr Dovzhenko completed his screenplay 'Ukraine in Flames,' only for Stalin to personally condemn it for 'nationalist moods' and bar the artist from ever returning to his homeland." },
  { country: "ua", year: 1944, category: "Upheaval", text: "Over three days beginning 18 May, the NKVD packed virtually the entire Crimean Tatar population, more than 190,000 people, into cattle trains and deported them to Central Asia on Stalin's collective-punishment order, where a large share soon died of hunger and disease." },
  { country: "ua", year: 1944, category: "Politics", text: "As the front swept westward and the Red Army crossed into Transcarpathia that autumn, a Mukachevo congress of people's committees on 26 November declared its wish to unite the region with the Soviet republic." },
  { country: "ua", year: 1945, category: "Politics", text: "On 26 June the republic signed the United Nations Charter in San Francisco as a founding member with its own General Assembly seat, a diplomatic device that gave Moscow three votes in the new world body." },
  { country: "ua", year: 1945, category: "People", text: "Fighter ace Ivan Kozhedub, who flew 330 combat sorties and was never once shot down, received his third Hero of the Soviet Union star that August after also becoming the first Soviet pilot to down a German Me 262 jet." },
  { country: "ua", year: 1945, category: "Politics", text: "On 29 June Czechoslovakia formally ceded Transcarpathia to the Soviet Union, an act that for the first time brought nearly all ethnically Ukrainian lands within a single state." },
  { country: "ua", year: 1946, category: "Everyday life", text: "The most severe drought since 1891 ruined the harvest while the state refused to lower grain quotas and cut ration eligibility, triggering a famine that would kill some 300,000 people in the republic alone." },
  { country: "ua", year: 1946, category: "Culture", text: "At a coerced 'synod' in Lviv on 8-10 March, the Soviet authorities forcibly abolished the Ukrainian Greek Catholic Church and absorbed its parishes into the Russian Orthodox Church, driving the faithful underground for over four decades." },
  { country: "ua", year: 1946, category: "Everyday life", text: "Transcarpathia, with its mountain villages and the town of Uzhhorod, was organized as the Zakarpattia oblast and began its absorption into Soviet economic and cultural life." },
  { country: "ua", year: 1947, category: "Politics", text: "On Stalin's orders Lazar Kaganovich replaced Nikita Khrushchev as party chief in the spring during the famine crisis, only for Khrushchev to be restored to the post by year's end." },
  { country: "ua", year: 1947, category: "Science & tech", text: "Power generation resumed at the rebuilt Dnieper hydroelectric station in March, its destroyed turbines replaced in part by new generators shipped from General Electric in America." },
  { country: "ua", year: 1947, category: "People", text: "Sofia Rotaru, who would become one of the Soviet Union's most beloved pop singers, was born on 7 August into an ethnic Moldovan family in a village in the Chernivtsi region." },
  { country: "ua", year: 1948, category: "Everyday life", text: "Mass starvation faded after a more successful harvest, but rural life remained grim as peasants labored on collective farms with little to show for it under a state that prized grain deliveries over their survival." },
  { country: "ua", year: 1949, category: "Politics", text: "Khrushchev's long tenure as the republic's party boss ended as he was recalled to Moscow in December, leaving behind a land where the postwar Sovietization of the newly annexed west and the suppression of the UPA insurgency continued." },
  { country: "ua", year: 1950, category: "Upheaval", text: "On 5 March, Roman Shukhevych, supreme commander of the Ukrainian Insurgent Army, was killed in a firefight with Soviet security troops who surrounded his hideout in the village of Bilohorshcha on the edge of Lviv, dealing a crippling blow to the nationalist underground." },
  { country: "ua", year: 1950, category: "Science & tech", text: "In September, work began on the lower Dnipro on the vast Kakhovka Hydroelectric Power Plant, a flagship of Stalin's 'Great Plan for the Transformation of Nature' that would drown villages to create an inland sea for electricity and irrigation." },
  { country: "ua", year: 1950, category: "People", text: "Viktor Yanukovych, a future president who would flee the country during the 2014 Euromaidan uprising, was born on 9 July in a village near the Donbas industrial town of Yenakiieve." },
  { country: "ua", year: 1951, category: "Upheaval", text: "Mass deportations from the western regions ground on, part of a postwar campaign that uprooted hundreds of thousands of people for resistance, religious loyalty, or refusal to join collective farms, many shipped to special settlements in Siberia and the far north." },
  { country: "ua", year: 1951, category: "Everyday life", text: "The Ukrainian Greek Catholic Church, formally liquidated at the Soviet-engineered Lviv 'sobor' of 1946, survived only as a clandestine network of priests holding secret liturgies in homes and forests under constant threat of arrest." },
  { country: "ua", year: 1952, category: "Science & tech", text: "Oleg Antonov's aircraft design bureau was relocated to Kyiv, planting the roots of an aviation industry that would one day build the world's largest cargo planes in the republic's capital." },
  { country: "ua", year: 1952, category: "Sport", text: "At Helsinki, the first Olympics the Soviet Union ever entered, gymnast Viktor Chukarin, a survivor of Nazi prison camps, emerged as the most decorated male athlete of the Games with four golds and two silvers." },
  { country: "ua", year: 1952, category: "Sport", text: "Poltava-born gymnast Nina Bocharova won Olympic gold on the balance beam and silver in the all-around at the Helsinki Games, becoming the first Olympic balance beam champion in history." },
  { country: "ua", year: 1953, category: "Politics", text: "In June, Oleksii Kyrychenko became First Secretary of the Communist Party of Ukraine, the first ethnic Ukrainian to lead the republic's party since the 1920s, signaling a partial softening of late-Stalinist Russification." },
  { country: "ua", year: 1953, category: "Everyday life", text: "After Stalin's death in March, a sweeping amnesty began emptying the labor camps, and over the following years hundreds of thousands of released prisoners made their way back to towns and villages across the republic." },
  { country: "ua", year: 1954, category: "Politics", text: "On 19 February the Crimean Peninsula was formally transferred from the Russian Federation to the Ukrainian republic by Soviet decree, justified by Crimea's economic dependence on the mainland and timed to a grand anniversary jubilee." },
  { country: "ua", year: 1954, category: "Culture", text: "Lavish state celebrations marked the 300th anniversary of the 1654 Pereiaslav Agreement binding the Cossack lands to Muscovy, and the town of Proskuriv was renamed Khmelnytskyi after the Cossack hetman." },
  { country: "ua", year: 1954, category: "Sport", text: "Dynamo Kyiv lifted the Soviet Cup for the first time, beating Spartak Yerevan in a rain-soaked Moscow final, an early triumph for the club that would become the standard-bearer of football in the republic." },
  { country: "ua", year: 1954, category: "People", text: "Viktor Yushchenko, the future president who would survive a dioxin poisoning and lead the 2004 Orange Revolution, was born on 23 February into a family of teachers in the village of Khoruzhivka in Sumy region." },
  { country: "ua", year: 1955, category: "Science & tech", text: "On 18 October the first turbine of the Kakhovka Hydroelectric Power Plant began generating power, and the rising waters started filling a reservoir that would eventually flood more than two thousand square kilometers of the Dnipro valley." },
  { country: "ua", year: 1955, category: "Everyday life", text: "A wide-ranging amnesty released most of the remaining camp inmates, returning veterans of the nationalist underground and ordinary prisoners alike to families that had often given them up for dead." },
  { country: "ua", year: 1956, category: "Politics", text: "Khrushchev's 'Secret Speech' denouncing Stalin's crimes at the 20th Party Congress in February opened the cultural and political loosening known as the Thaw, easing censorship and accelerating the rehabilitation of purge victims." },
  { country: "ua", year: 1956, category: "People", text: "On 25 November, the pioneering filmmaker Oleksandr Dovzhenko, master of poetic cinema, died of a heart attack at his dacha near Moscow with several cherished projects still unmade." },
  { country: "ua", year: 1957, category: "Politics", text: "Oleksii Kyrychenko was promoted to Moscow as a close Khrushchev ally, becoming the second-highest-ranking figure in the entire Soviet party leadership after Khrushchev himself." },
  { country: "ua", year: 1957, category: "Culture", text: "The Kyiv film studio was officially named the Dovzhenko Film Studio in memory of the director who had died the year before, cementing it as the heart of the republic's cinema." },
  { country: "ua", year: 1958, category: "Science & tech", text: "Kharkiv's heavy-engineering works built three giant tracked 'Kharkovchanka' polar cruisers, mobile homes-on-treads with bunks, a galley and a workshop, designed to carry Soviet scientists across the Antarctic ice." },
  { country: "ua", year: 1959, category: "Science & tech", text: "Kharkiv-built Kharkovchanka cruisers hauled a Soviet expedition all the way to the geographic South Pole in December, demonstrating the engineering muscle of the republic's heavy industry." },
  { country: "ua", year: 1959, category: "Sport", text: "On 29 May, the 20-year-old Valeriy Lobanovskyi made his top-flight debut for Dynamo Kyiv against the army club of Moscow, beginning a career that would later make him one of football's most influential coaches." },
  { country: "ua", year: 1960, category: "Science & tech", text: "On 6 November, the anniversary of the October Revolution, the capital opened its first underground railway, a single 5.24-kilometre line of five stations that became the Soviet Union's third metro after Moscow and Leningrad." },
  { country: "ua", year: 1960, category: "Science & tech", text: "Among the newly opened metro stations was Arsenalna, sunk about 105 metres beneath the high bank of the Dnipro and reached by a five-minute escalator ride, making it the deepest underground station in the world." },
  { country: "ua", year: 1960, category: "Sport", text: "At the Rome Olympics, Kherson-born gymnast Larisa Latynina anchored the Soviet women's team to gold and defended her individual all-around title, on her way to a career haul of a record eighteen Olympic medals." },
  { country: "ua", year: 1960, category: "People", text: "In Dnipropetrovsk on 27 November, Yulia Tymoshenko was born, the future twice prime minister and a central figure of the country's post-Soviet political dramas." },
  { country: "ua", year: 1961, category: "Sport", text: "Dynamo Kyiv won the Soviet top-flight football championship, the first time any club from outside Moscow had broken the capital's hegemony, with the corner-kick specialist Valeriy Lobanovskyi scoring ten goals from the left wing." },
  { country: "ua", year: 1961, category: "Upheaval", text: "On 13 March a dam holding back a decade's worth of liquid industrial waste pumped into the Babyn Yar ravine burst after heavy rain, sending a wall of mud through the Kurenivka district of the capital and killing as many as 1,500 people in minutes." },
  { country: "ua", year: 1961, category: "Politics", text: "Volodymyr Shcherbytsky became chairman of the republic's Council of Ministers, beginning a long rise to power for a man who would dominate its politics into the 1980s." },
  { country: "ua", year: 1961, category: "Everyday life", text: "Low-cost five-storey concrete apartment blocks nicknamed 'khrushchyovky' were rising across the capital, their cramped flats with tiny kitchens and thin walls offering millions their first family home of their own." },
  { country: "ua", year: 1962, category: "Everyday life", text: "A nationwide announcement on 31 May that meat would cost 30 percent more and butter a quarter more sparked unrest across the Soviet Union, after which the state froze the prices of basic foodstuffs for decades rather than risk further protest." },
  { country: "ua", year: 1962, category: "Culture", text: "Vasyl Symonenko, a leading young voice of the Sixtiers literary generation, published his debut poetry collection 'Silence and Thunder', which helped revive a confident Ukrainian-language verse." },
  { country: "ua", year: 1963, category: "Politics", text: "Petro Shelest, a native of the Kharkiv region, took charge of the republic's Communist Party, a leader who would cautiously balance loyalty to Moscow with quiet defence of national culture until his removal in 1972." },
  { country: "ua", year: 1963, category: "Culture", text: "Censors suppressed poet Lina Kostenko's collection 'The Stellar Integral' as ideologically harmful, beginning a publication freeze that would keep one of the country's finest poets silent until 1977." },
  { country: "ua", year: 1963, category: "People", text: "On 13 December the poet Vasyl Symonenko died in Cherkasy at just 28, weeks after a brutal beating by security operatives, his early death galvanising the national dissident movement." },
  { country: "ua", year: 1963, category: "People", text: "In Luhansk on 4 December was born Serhiy Bubka, the pole vaulter who would become the first to clear six metres and break the world record thirty-five times." },
  { country: "ua", year: 1964, category: "Culture", text: "Sergei Parajanov made 'Shadows of Forgotten Ancestors' at the Dovzhenko Studio in Kyiv, a luminous film shot in the Hutsul dialect of Ukrainian in the Carpathian village of Kryvorivnia that became a landmark of the country's cinema." },
  { country: "ua", year: 1964, category: "Culture", text: "The artist Alla Horska and her collaborators created a stained-glass window depicting the poet Taras Shevchenko for Kyiv University, only to see it condemned as ideologically hostile and destroyed, with the artists expelled from the Soviet Artists' Union." },
  { country: "ua", year: 1964, category: "Sport", text: "At the Tokyo Olympics, Kherson-born gymnast Larisa Latynina won gold in the floor exercise and the team event in her final Games, completing an Olympic career of unmatched success." },
  { country: "ua", year: 1965, category: "Science & tech", text: "On 27 February the Antonov An-22 'Antei', designed in Kyiv and the largest turboprop aircraft ever built, made its maiden flight, later wowing crowds at the Paris Air Show." },
  { country: "ua", year: 1965, category: "Upheaval", text: "From late August the authorities launched a sweeping crackdown on intellectuals tied to the Sixtiers movement, a purge that would detain around two hundred people and snuff out the cultural thaw." },
  { country: "ua", year: 1965, category: "Culture", text: "Writer Ivan Dziuba composed 'Internationalism or Russification?', a treatise sent to party leaders that argued from Lenin's own words against the Russification of the republic and circulated widely as underground samvydav." },
  { country: "ua", year: 1965, category: "Politics", text: "The Kosygin economic reform reached the republic, re-establishing the central industrial ministries while granting individual enterprises modest new powers over profit and bonuses in a limited bid to revive a stagnating economy." },
  { country: "ua", year: 1966, category: "Science & tech", text: "On 14 January Sergei Korolev, the rocket designer born in Zhytomyr who masterminded the Soviet space programme and Gagarin's flight, died in Moscow with his identity still a state secret to the public." },
  { country: "ua", year: 1966, category: "Sport", text: "Dynamo Kyiv, drilled in fitness and pressing tactics by coach Viktor Maslov, won both the Soviet championship and the Soviet Cup, opening a run of three consecutive league titles through 1968." },
  { country: "ua", year: 1966, category: "Culture", text: "At the republic's Writers' Congress, party chief Petro Shelest delivered a speech widely understood as offering quiet encouragement to the Ukrainian intelligentsia." },
  { country: "ua", year: 1967, category: "Culture", text: "Alla Horska and fellow monumentalists created bold mosaic panels including 'Tree of Life' and 'Boryviter' for a restaurant in Mariupol, bringing a distinctive national modernism to its walls." },
  { country: "ua", year: 1968, category: "Upheaval", text: "In April 139 Kyiv scientists and cultural figures, the artist Alla Horska among them, signed an open letter of protest to Soviet leaders against the closed political trials of dissidents." },
  { country: "ua", year: 1969, category: "Science & tech", text: "The giant Kyiv-designed Antonov An-22 transport reached the front line, the first aircraft delivered to a Soviet military transport base, giving the armed forces an unrivalled heavy-lift workhorse." },
  { country: "ua", year: 1970, category: "Culture", text: "On 13 September the lilting song \"Chervona Ruta\" by 19-year-old composer Volodymyr Ivasiuk had its public premiere on a live television broadcast from Chernivtsi, soon becoming an unofficial anthem of the nation's pop music." },
  { country: "ua", year: 1970, category: "Everyday life", text: "On 4 February the model atomgrad town of Pripyat was founded beside the Pripyat River to house the workers who would one day run the reactors of a vast new nuclear power station." },
  { country: "ua", year: 1970, category: "Everyday life", text: "Young families typically waited years on official lists for a tiny two-room flat in a prefabricated apartment block, regarding the move out of a shared communal apartment as one of life's great achievements despite the paper-thin walls." },
  { country: "ua", year: 1971, category: "Culture", text: "Yuri Ilyenko's visually lush poetic-cinema drama \"The White Bird Marked with Black,\" set in a Hutsul Carpathian village, won the Golden Prize at the Moscow International Film Festival before being condemned and shelved by Communist Party authorities." },
  { country: "ua", year: 1971, category: "Culture", text: "Performed by the folk-flavoured vocal-instrumental ensemble Smerichka, the song \"Chervona Ruta\" won the USSR \"Song of the Year\" title at the televised gala in Moscow." },
  { country: "ua", year: 1972, category: "Politics", text: "Volodymyr Shcherbytsky, a loyal ally of Leonid Brezhnev, replaced the relatively nationally minded Petro Shelest as Communist Party first secretary and would dominate the republic until 1989." },
  { country: "ua", year: 1972, category: "Upheaval", text: "In a sweeping January crackdown known as the \"general pogrom,\" the KGB arrested dozens of intellectuals including the poet Vasyl Stus and the journalist Viacheslav Chornovil, with some 89 dissidents convicted that year." },
  { country: "ua", year: 1972, category: "Sport", text: "Sprinter Valeriy Borzov, born in Sambir, won both the 100 and 200 metres at the Munich Olympics, remaining the only European man ever to complete that double." },
  { country: "ua", year: 1973, category: "Politics", text: "A two-year purge of scholarly and cultural institutions supervised by new ideology chief Valentyn Malanchuk saw expulsions from the Academy of Sciences, universities, editorial boards, and the writers', artists' and filmmakers' unions." },
  { country: "ua", year: 1973, category: "People", text: "Andriy Danylko, later world-famous as the flamboyant drag stage persona Verka Serduchka, was born into a working-class family in Poltava on 2 October." },
  { country: "ua", year: 1973, category: "Everyday life", text: "The locally built ZAZ Zaporozhets 968A, the cheapest car in the whole Soviet Union, went on sale with such modern touches as a collapsible steering column and a padded dashboard." },
  { country: "ua", year: 1973, category: "Sport", text: "Valeriy Lobanovskyi took charge of football club Dynamo Kyiv, applying a data-driven, science-based training method developed with researcher Anatoliy Zelentsov that emphasised relentless pressing." },
  { country: "ua", year: 1974, category: "Sport", text: "In Lobanovskyi's first full season Dynamo Kyiv swept to the Soviet league and cup double, with striker Oleh Blokhin finishing the league's top scorer and being crowned Soviet Footballer of the Year." },
  { country: "ua", year: 1974, category: "Politics", text: "Two years after the wave of arrests known as the 'general pogrom,' a generation of the nation's writers and activists, among them the poets Vasyl Stus and Ihor Kalynets and the critic Ivan Svitlychny, languished in distant labour camps as party boss Volodymyr Shcherbytsky pressed his drive to Russify schools and universities." },
  { country: "ua", year: 1975, category: "Sport", text: "Dynamo Kyiv beat Hungary's Ferencvaros 3-0 in Basel on 14 May to lift the European Cup Winners' Cup, becoming the first Soviet club ever to win a major European trophy." },
  { country: "ua", year: 1975, category: "Sport", text: "Forward Oleh Blokhin scored in both legs as Dynamo Kyiv thrashed Bayern Munich 3-0 on aggregate for the European Super Cup, and in December he was awarded the Ballon d'Or as Europe's best footballer." },
  { country: "ua", year: 1975, category: "Everyday life", text: "On 23 August the city of Kharkiv opened the first eight-station stretch of its new underground metro, becoming only the sixth city in the USSR and the second in the republic to gain a subway." },
  { country: "ua", year: 1975, category: "People", text: "Actress and model Milla Jovovich, later a Hollywood star, was born in Kyiv on 17 December." },
  { country: "ua", year: 1976, category: "Politics", text: "On 9 November the Ukrainian Helsinki Group was founded in Kyiv by ten activists, among them writer Mykola Rudenko, to monitor Soviet compliance with the human-rights promises of the Helsinki Accords." },
  { country: "ua", year: 1976, category: "People", text: "Andriy Shevchenko, who would become the nation's greatest footballer and a Ballon d'Or winner, was born on 29 September in the village of Dvirkivshchyna." },
  { country: "ua", year: 1977, category: "Science & tech", text: "On 26 September the first reactor unit of the Chernobyl nuclear power station was commissioned, the inaugural block of what would grow into a four-reactor complex and the first nuclear plant on the republic's soil." },
  { country: "ua", year: 1977, category: "Science & tech", text: "On 31 August the Antonov An-72, the design bureau's first jet-powered transport, nicknamed Cheburashka for its over-wing engine intakes, made its maiden flight." },
  { country: "ua", year: 1978, category: "Politics", text: "A new resolution intensified Russian-language teaching from the earliest grades in the republic's schools, deepening a steady decline of the native language under Shcherbytsky's rule." },
  { country: "ua", year: 1978, category: "Everyday life", text: "After lean harvests earlier in the decade had forced grain imports, the fields delivered a record harvest, reflecting the republic's role as the agricultural heart of the Soviet Union." },
  { country: "ua", year: 1979, category: "Culture", text: "The body of beloved composer Volodymyr Ivasiuk, author of \"Chervona Ruta,\" was found hanged in a forest near Lviv in May, weeks after he vanished; the official suicide verdict was widely disbelieved and the death is often blamed on the KGB." },
  { country: "ua", year: 1980, category: "Sport", text: "When the United States and dozens of allies boycotted the Moscow Summer Olympics over the invasion of Afghanistan, preliminary football matches were still played before crowds at the 100,000-seat Republican Stadium in the capital." },
  { country: "ua", year: 1980, category: "Sport", text: "Odessa-born gymnast Stella Zakharova helped the Soviet women's team to Olympic gold and dazzled judges as the first woman to perform three double back somersaults in a floor routine." },
  { country: "ua", year: 1980, category: "Everyday life", text: "In a republic of famously fertile black earth, shoppers still queued for hours and relied on personal connections, the blat network, to obtain sausage, fish or oranges, while party officials enjoyed crab, caviar and Swiss cheese." },
  { country: "ua", year: 1980, category: "Culture", text: "American-born soprano Kvitka Cisyk released her first album of Ukrainian songs, 'Kvitka, Songs of Ukraine,' lovingly preserving the folk repertoire abroad while it was suppressed at home." },
  { country: "ua", year: 1980, category: "Politics", text: "Veteran dissident and Helsinki Group member Vyacheslav Chornovil was arrested yet again, this time on fabricated charges, as the hardline Russification drive of party boss Volodymyr Shcherbytsky pressed on." },
  { country: "ua", year: 1981, category: "Culture", text: "On 9 May Leonid Brezhnev inaugurated the Motherland Monument high above the Dnipro in the capital, a 62-metre stainless-steel woman raising a sword and shield atop a vast new museum of the Great Patriotic War." },
  { country: "ua", year: 1981, category: "Sport", text: "Dynamo Kyiv were crowned Soviet champions for a tenth time, confirming the Kyiv club, and the cluster of Ukrainian stars at its heart, as the dominant force in all-Union football." },
  { country: "ua", year: 1981, category: "Politics", text: "By now most founders of the Ukrainian Helsinki Group, set up in 1976 to monitor Moscow's compliance with the human-rights pledges of the Helsinki Accords, had been broken and shipped to the camps, among them its writer-founder Mykola Rudenko and the veteran activist Oksana Meshko." },
  { country: "ua", year: 1982, category: "Science & tech", text: "On 24 December the Antonov An-124 Ruslan, then the largest transport aircraft in the world, made its maiden flight from the Sviatoshyn aerodrome in the capital, capable of hauling 150 tonnes of cargo." },
  { country: "ua", year: 1983, category: "Culture", text: "Censors so heavily mutilated Kira Muratova's film 'Among the Grey Stones' that the Odessa director disowned it, removing her name from the credits in protest." },
  { country: "ua", year: 1984, category: "Sport", text: "Donetsk pole vaulter Sergey Bubka set the first of his many world records, clearing 5.85 metres in May and beginning a reign that would redefine the event." },
  { country: "ua", year: 1984, category: "People", text: "Cardinal Josyf Slipyj, who had survived nearly two decades in Soviet labour camps, died in Rome, where Pope John Paul II personally came to honour the leader of the banned, catacomb Greek Catholic Church." },
  { country: "ua", year: 1985, category: "Sport", text: "On 13 July in Paris, Sergey Bubka became the first human to pole vault over six metres, earning a standing ovation after flying in from Moscow only that morning." },
  { country: "ua", year: 1985, category: "Everyday life", text: "Gorbachev's new anti-alcohol campaign hit the southern republic hard, as roughly a third of Crimea's vineyards were uprooted and rare grape varieties were lost." },
  { country: "ua", year: 1986, category: "Upheaval", text: "At 1:23 a.m. on 26 April, reactor No. 4 of the Chernobyl plant near Pripyat exploded during a botched safety test, hurling more than fifty tonnes of radioactive material into the air in history's worst nuclear accident." },
  { country: "ua", year: 1986, category: "Upheaval", text: "The day after the explosion, the roughly 49,000 residents of Pripyat were evacuated by a long column of buses, abandoning a brand-new city that became a frozen ghost town." },
  { country: "ua", year: 1986, category: "Politics", text: "Despite radiation drifting over the capital, the authorities went ahead with the May Day parade on Khreshchatyk, and Shcherbytsky was ordered to march through it with his own grandchildren." },
  { country: "ua", year: 1986, category: "Sport", text: "Dynamo Kyiv, coached by Valeriy Lobanovskyi, thrashed Atletico Madrid 3-0 in Lyon on 2 May to win the European Cup Winners' Cup, with goals from Zavarov, Blokhin and Yevtushenko." },
  { country: "ua", year: 1986, category: "Sport", text: "Dynamo Kyiv striker Igor Belanov was crowned European Footballer of the Year, winning the Ballon d'Or after a season capped by a hat-trick against Belgium at the World Cup in Mexico." },
  { country: "ua", year: 1986, category: "Science & tech", text: "Around 200,000 'liquidators' from across the Soviet Union toiled through the year to bury the wreckage and entomb the ruined reactor in a vast concrete sarcophagus completed by late November." },
  { country: "ua", year: 1987, category: "Politics", text: "From 7 to 30 July a court convened in the House of Culture of the evacuated town of Chernobyl tried the men blamed for the disaster, sentencing plant director Viktor Bryukhanov, chief engineer Nikolai Fomin and deputy Anatoly Dyatlov each to ten years in a labour camp in a trial staged as a showcase of Gorbachev's new openness." },
  { country: "ua", year: 1987, category: "Politics", text: "As glasnost loosened the regime's grip, dissidents gathered in a Kyiv coffeehouse on 8 June to found the Ukrainian Culturological Club, the first openly independent civic association in the republic in decades." },
  { country: "ua", year: 1987, category: "Culture", text: "In Lviv on 19 October young activists founded the Lion Society, a student-led group devoted to reviving Ukrainian language, history and heritage that would help drive the national awakening of the years to come." },
  { country: "ua", year: 1988, category: "Politics", text: "Under Gorbachev's amnesty for political prisoners, released dissidents led by Vyacheslav Chornovil revived the human-rights cause by founding the Ukrainian Helsinki Union." },
  { country: "ua", year: 1989, category: "Upheaval", text: "In July half a million coal miners in the Donbas and across the USSR downed tools, winning concessions on food, soap and housing in a wave of strikes often called the spark of the 1989-1991 Ukrainian revolution." },
  { country: "ua", year: 1989, category: "Politics", text: "Rukh, the People's Movement of Ukraine, held its founding congress on 8-10 September with poet Ivan Drach as its first leader, swiftly becoming a mass force for democratic and national revival." },
  { country: "ua", year: 1989, category: "Politics", text: "Amid mounting protests, Gorbachev intervened personally to remove the long-serving hardliner Volodymyr Shcherbytsky as Communist Party chief, ending an era of Russification and neo-Stalinist rule." },
  { country: "ua", year: 1989, category: "Culture", text: "On 28 October the republic's Supreme Soviet adopted the Law on Languages, declaring Ukrainian the state language after decades of creeping Russification." },
  { country: "ua", year: 1989, category: "People", text: "On the eve of Gorbachev's meeting with Pope John Paul II, the Soviet government finally let the banned Greek Catholic Church emerge from four decades underground and register its parishes again." },
  { country: "ua", year: 1989, category: "Culture", text: "Kira Muratova's bleak, fragmentary masterpiece 'The Asthenic Syndrome' captured the exhaustion of late Soviet life and went on to win a Silver Bear at Berlin despite years of censorship of her work." },
  { country: "ua", year: 1990, category: "Upheaval", text: "On 21 January more than 300,000 people joined hands in a roughly 480-kilometre human chain stretching from Lviv and Ivano-Frankivsk to the capital, echoing the Baltic Way to demand unity and a peaceful break from the Soviet Union." },
  { country: "ua", year: 1990, category: "Politics", text: "On 16 July the parliament in Kyiv adopted the Declaration of State Sovereignty by a vote of 355 to 4, asserting that republican law took precedence over Soviet law and that the republic would maintain its own army, central bank and currency." },
  { country: "ua", year: 1990, category: "Upheaval", text: "In October hundreds of students pitched tents and began a hunger strike on the central square of the capital in the 'Revolution on Granite,' forcing the resignation of the prime minister after sixteen days." },
  { country: "ua", year: 1990, category: "Everyday life", text: "As the Soviet command economy unravelled, the republic began issuing coupons alongside near-worthless rubles so residents could buy groceries and basic essentials amid mounting shortages and queues." },
  { country: "ua", year: 1991, category: "Culture", text: "The second Chervona Ruta festival of Ukrainian-language music was deliberately staged in heavily Russified Zaporizhzhia, introducing acts like the future Skriabin and giving eastern audiences a glimpse of a possible independent national culture." },
  { country: "ua", year: 1991, category: "Politics", text: "On 24 August the parliament declared full independence, a decision then put to the people for ratification in a December referendum." },
  { country: "ua", year: 1991, category: "Upheaval", text: "On 11 October a turbine in reactor No. 2 at the Chernobyl plant caught fire after an electrical surge, leading to that unit's permanent shutdown." },
  { country: "ua", year: 1991, category: "Politics", text: "On 1 December roughly 84 percent of voters turned out and about 92 percent endorsed independence, the same day electing Leonid Kravchuk as the first president." },
  { country: "ua", year: 1991, category: "Science & tech", text: "With the Soviet Union dissolving in December, the Antonov An-225 Mriya, the heaviest aircraft ever built and originally designed to ferry the Buran space shuttle, became a national asset before being mothballed for lack of funds." },
  { country: "ua", year: 1992, category: "Everyday life", text: "On 10 January the karbovanets coupon replaced the ruble at par as everyday money, even as shop shelves stayed bare, weekend markets thrived and the new currency steadily lost value." },
  { country: "ua", year: 1992, category: "Politics", text: "A dispute with Russia over the former Soviet Black Sea Fleet and basing rights in Sevastopol flared into open rivalry in April when Boris Yeltsin and Leonid Kravchuk issued duelling decrees each claiming the fleet." },
  { country: "ua", year: 1993, category: "Everyday life", text: "Hyperinflation ran out of control, reaching an annual rate of more than 4,700 percent, with the karbovanets collapsing against the dollar and a minimum wage worth barely a couple of dollars a month." },
  { country: "ua", year: 1993, category: "Sport", text: "In February the pole vaulter Sergey Bubka, the first man ever to clear six metres, set the last of his world records indoors in his home city of Donetsk." },
  { country: "ua", year: 1993, category: "Upheaval", text: "In June a sharp jump in staple prices triggered a coal miners' strike across the Donbas involving hundreds of thousands of workers, the largest single protest the young state had seen." },
  { country: "ua", year: 1994, category: "Politics", text: "Early presidential elections in June and July produced the first peaceful transfer of power within the former Soviet Union, as Leonid Kuchma defeated the incumbent Kravchuk, who accepted defeat." },
  { country: "ua", year: 1994, category: "Upheaval", text: "In Crimea the pro-Russian Yuriy Meshkov was elected president of the peninsula on a separatist platform with nearly 73 percent of the vote, opening a standoff with Kyiv." },
  { country: "ua", year: 1994, category: "Politics", text: "On 5 December the Budapest Memorandum was signed, securing the country's agreement to give up the world's third-largest nuclear arsenal in exchange for security assurances from Russia, the United States and Britain." },
  { country: "ua", year: 1994, category: "People", text: "On 12 September the future tennis star Elina Svitolina, who would become the highest-ranked Ukrainian woman in history, was born in Odesa." },
  { country: "ua", year: 1995, category: "Politics", text: "Parliament responded to the Crimean separatist crisis by scrapping the peninsula's constitution and abolishing its presidency, sidelining and exiling the would-be breakaway leader." },
  { country: "ua", year: 1996, category: "Politics", text: "On 28 June, after an all-night session, parliament adopted the country's first post-Soviet constitution, confirming Ukrainian as the sole state language." },
  { country: "ua", year: 1996, category: "Sport", text: "At the Atlanta Olympics, the country's first as an independent nation, gymnast Lilia Podkopayeva won the all-around and floor exercise titles while teenage boxer Wladimir Klitschko took super-heavyweight gold." },
  { country: "ua", year: 1996, category: "Everyday life", text: "In a monetary reform run from 2 to 16 September, the hyperinflated karbovanets was swapped for the new hryvnia at a rate of 100,000 to 1, a stabilisation that launched the political career of central banker Viktor Yushchenko." },
  { country: "ua", year: 1996, category: "Upheaval", text: "On 30 November, under pressure from foreign governments, reactor No. 1 at the Chernobyl plant was shut down as the country wound the stricken site toward closure." },
  { country: "ua", year: 1997, category: "Politics", text: "On 28 May the prime ministers of the two countries signed the Partition Treaty dividing the former Soviet Black Sea Fleet, with Russia taking the larger share and leasing naval facilities in Sevastopol." },
  { country: "ua", year: 1997, category: "Culture", text: "Vopli Vidopliasova, pioneers of singing rock in Ukrainian rather than Russian, released the hit song 'Vesna' ('Spring'), which became one of the era's most beloved national anthems of renewal." },
  { country: "ua", year: 1997, category: "Science & tech", text: "On 19 November Leonid Kadenyuk flew aboard the U.S. space shuttle Columbia as a payload specialist, becoming the first astronaut of the independent nation and conducting plant-growth experiments in orbit." },
  { country: "ua", year: 1998, category: "Sport", text: "Andriy Shevchenko, who had debuted for Dynamo Kyiv as an 18-year-old in 1994, helped power the club's revival under coach Valeriy Lobanovskyi toward Europe's elite." },
  { country: "ua", year: 1999, category: "Politics", text: "On 21 January President Kuchma decreed a new national holiday, Unity Day, to be marked each 22 January in memory of the 1919 act uniting the eastern and western Ukrainian republics." },
  { country: "ua", year: 1999, category: "Sport", text: "On 7 April Dynamo Kyiv drew 3-3 with Bayern Munich, with Shevchenko scoring twice, in the club's first Champions League semi-final." },
  { country: "ua", year: 2000, category: "Politics", text: "Opposition journalist Georgiy Gongadze, co-founder of the muckraking website Ukrainska Pravda, was abducted in September and later found beheaded in a forest outside the capital, igniting a political earthquake." },
  { country: "ua", year: 2000, category: "Upheaval", text: "In November a socialist deputy played secretly recorded tapes that seemed to capture the president ordering the journalist's removal, launching the 'Cassette Scandal' and the 'Ukraine Without Kuchma' protest movement." },
  { country: "ua", year: 2000, category: "Sport", text: "Swimmer Yana Klochkova, nicknamed the 'Medley Queen,' won two Olympic golds and set a world record in the 400-metre individual medley at the Sydney Games." },
  { country: "ua", year: 2001, category: "Everyday life", text: "The country's first and only post-independence census counted just over 48 million people, down more than three million from the late-Soviet tally a dozen years earlier." },
  { country: "ua", year: 2001, category: "People", text: "Mykhailo Mudryk, who would grow up to become the country's most expensive footballer in a record move to Chelsea, was born on 5 January in the Kharkiv region." },
  { country: "ua", year: 2002, category: "Upheaval", text: "On 27 July a Su-27 fighter plummeted into spectators at an air show near Lviv, killing 77 people and injuring hundreds in what remains the deadliest air-show disaster in history." },
  { country: "ua", year: 2003, category: "Culture", text: "Oles Sanin's folkloric Cossack drama 'Mamay,' shot in just 24 days, became only the second film ever submitted by the country for the Academy Award for Best Foreign Language Film." },
  { country: "ua", year: 2003, category: "Sport", text: "Heavyweight Vitali Klitschko lost to Lennox Lewis only because the fight was stopped on a gruesome cut, even though he was leading on all three scorecards, setting up his world-title triumph the following year." },
  { country: "ua", year: 2004, category: "Culture", text: "Singer Ruslana stormed to victory at the Eurovision Song Contest in Istanbul with the leather-clad, drum-driven 'Wild Dances,' winning 280 points and the country's first crown." },
  { country: "ua", year: 2004, category: "Sport", text: "AC Milan striker Andriy Shevchenko was awarded the Ballon d'Or, becoming the third footballer from the country to win Europe's top individual prize after Oleh Blokhin and Igor Belanov." },
  { country: "ua", year: 2004, category: "People", text: "Opposition presidential candidate Viktor Yushchenko was poisoned with pure dioxin at a September dinner, his face left badly scarred by chloracne after his blood showed levels some 50,000 times above normal." },
  { country: "ua", year: 2004, category: "Upheaval", text: "After a fraud-marred run-off vote, hundreds of thousands camped out in orange in the capital's main square through bitter cold in the Orange Revolution until the Supreme Court annulled the result." },
  { country: "ua", year: 2004, category: "Politics", text: "In a court-ordered re-run of the presidential run-off on 26 December, Viktor Yushchenko was elected with about 52 percent of the vote, overturning the disputed official result." },
  { country: "ua", year: 2005, category: "Politics", text: "Yushchenko was sworn in as president on 23 January before a vast crowd, formally bringing the Orange Revolution to its close and ushering in a pro-Western government." },
  { country: "ua", year: 2006, category: "Upheaval", text: "On New Year's Day Gazprom began cutting the gas flowing through the country, briefly dropping pressure in pipelines across Europe before a deal restored supplies a few days later." },
  { country: "ua", year: 2006, category: "Sport", text: "On its first-ever World Cup appearance the national football team beat Switzerland on penalties without conceding a single spot-kick to reach the quarter-finals in Germany." },
  { country: "ua", year: 2006, category: "Culture", text: "A government decree began phasing in mandatory dubbing of foreign films into Ukrainian in cinemas, a contentious cultural shift cheered in the west and resented in Russian-speaking cities." },
  { country: "ua", year: 2006, category: "Politics", text: "On 28 November parliament passed a law formally declaring the 1932-33 famine, the Holodomor, an act of genocide against the Ukrainian people." },
  { country: "ua", year: 2007, category: "Culture", text: "Comedian Andriy Danylko, performing in his glittering drag persona Verka Serduchka, finished a memorable second at Eurovision with the multilingual romp 'Dancing Lasha Tumbai.'" },
  { country: "ua", year: 2007, category: "Everyday life", text: "As seven straight years of roughly seven-percent growth nurtured a new urban middle class, the Lviv rock band Okean Elzy was crowned the best live act in the post-Soviet space." },
  { country: "ua", year: 2008, category: "Politics", text: "On 16 May the country became the 152nd member of the World Trade Organization, capping nearly fifteen years of accession negotiations." },
  { country: "ua", year: 2008, category: "Politics", text: "At the Bucharest summit in April NATO declared the country would one day become a member but, under French and German pressure, withheld the Membership Action Plan it had sought." },
  { country: "ua", year: 2008, category: "Everyday life", text: "The global financial crisis battered the steel-export economy late in the year, sending the hryvnia tumbling against the dollar and forcing an emergency loan from the IMF." },
  { country: "ua", year: 2009, category: "Upheaval", text: "A New Year gas standoff escalated into a thirteen-day cutoff of all Russian gas transiting the country, leaving homes across south-eastern Europe cold in midwinter until Putin and Tymoshenko struck a ten-year deal." },
  { country: "ua", year: 2009, category: "Politics", text: "Former interior ministry general Oleksiy Pukach was arrested over the 2000 murder of journalist Georgiy Gongadze, reportedly admitting his role nearly a decade after the killing." },
  { country: "ua", year: 2010, category: "Politics", text: "After a tight runoff, Viktor Yanukovych narrowly defeated Prime Minister Yulia Tymoshenko in the February presidential election, reversing the outcome of the 2004 Orange Revolution and tilting the country back toward Moscow." },
  { country: "ua", year: 2010, category: "Politics", text: "In April, President Yanukovych and Russia's Dmitry Medvedev signed the Kharkiv Pact, extending Russia's lease on the Black Sea Fleet's base in Sevastopol until 2042 in exchange for a thirty percent discount on Russian natural gas." },
  { country: "ua", year: 2011, category: "Sport", text: "Brothers Vitali and Wladimir Klitschko entered the Guinness World Records as the siblings with the most heavyweight world title fight wins, dominating boxing's heavyweight division as a pair." },
  { country: "ua", year: 2011, category: "People", text: "Former prime minister Yulia Tymoshenko, the braided heroine of the Orange Revolution, was sentenced to seven years in prison over a gas deal with Russia, a prosecution widely condemned abroad as politically motivated." },
  { country: "ua", year: 2012, category: "Sport", text: "Together with Poland, the country co-hosted the UEFA European Football Championship, with the final played at Kyiv's Olympic Stadium where Spain beat Italy 4-0." },
  { country: "ua", year: 2012, category: "People", text: "At Euro 2012, veteran captain Andriy Shevchenko scored two headers to beat Sweden 2-1 in the opening match, his last hurrah before retiring as his country's all-time top scorer with 48 international goals." },
  { country: "ua", year: 2012, category: "Culture", text: "The electro-folk band ONUKA was founded by Nata Zhyzhchenko and Yevhen Filatov, blending traditional instruments like the bandura and sopilka with pulsing electronic arrangements." },
  { country: "ua", year: 2013, category: "Upheaval", text: "When the president abruptly refused to sign an association agreement with the European Union in November, students gathered on Kyiv's Independence Square, igniting the months-long Euromaidan protests." },
  { country: "ua", year: 2013, category: "Everyday life", text: "On a cold December night, demonstrators toppling the granite Lenin statue on Kyiv's Bessarabska Square set off the wave of dismantled monuments that came to be nicknamed 'Leninopad,' or 'Leninfall.'" },
  { country: "ua", year: 2014, category: "Upheaval", text: "On 20 February, the deadliest day of the uprising, snipers fired on demonstrators in central Kyiv, and the roughly one hundred protesters killed during the revolution came to be honored as the 'Heavenly Hundred.'" },
  { country: "ua", year: 2014, category: "Politics", text: "After President Yanukovych fled the country in late February, parliament voted 328 to nil to remove him from office and call new elections, ending his rule." },
  { country: "ua", year: 2014, category: "Upheaval", text: "From late February into March, unmarked Russian soldiers known as 'little green men' seized Crimea, and Moscow formally annexed the peninsula after a referendum recognized by almost no other country." },
  { country: "ua", year: 2014, category: "Upheaval", text: "On 17 July, a Russian-made Buk missile shot down Malaysia Airlines Flight 17 over the war-torn Donbas, killing all 298 people aboard the Amsterdam-to-Kuala-Lumpur flight." },
  { country: "ua", year: 2014, category: "Everyday life", text: "The currency went into free fall after the central bank let it float, with the hryvnia eventually losing roughly seventy percent of its value against the dollar amid soaring prices for ordinary goods." },
  { country: "ua", year: 2014, category: "Politics", text: "Confectionery tycoon Petro Poroshenko, nicknamed the 'Chocolate King' for his Roshen brand, was elected president in May as the country reeled from revolution and the loss of Crimea." },
  { country: "ua", year: 2015, category: "Upheaval", text: "In January, the besieged 'Cyborgs' who had defended Donetsk International Airport for 242 days were finally overrun by Russian-backed forces." },
  { country: "ua", year: 2015, category: "Politics", text: "In February, leaders meeting in Belarus signed the Minsk II agreement, a fragile ceasefire deal struck just as Ukrainian troops were being pushed out of the railway hub of Debaltseve." },
  { country: "ua", year: 2015, category: "Everyday life", text: "By mid-year the war in the east and the loss of Crimea had displaced more than 1.3 million people within the country, who crowded into rented rooms and shelters in cities like Kharkiv and Kyiv." },
  { country: "ua", year: 2015, category: "Politics", text: "President Poroshenko signed decommunization laws in May, banning Soviet symbols and triggering the mass renaming of tens of thousands of streets and dozens of towns named for Communist figures." },
  { country: "ua", year: 2015, category: "People", text: "A Russian court sentenced Crimean filmmaker Oleg Sentsov to twenty years in prison on fabricated terrorism charges, and he defiantly sang the national anthem after the verdict was read." },
  { country: "ua", year: 2016, category: "Culture", text: "Singer Jamala won the Eurovision Song Contest with '1944,' a haunting song partly in the Crimean Tatar language about the Stalin-era deportation of her people, scoring a record 534 points." },
  { country: "ua", year: 2016, category: "Sport", text: "Gymnast Oleg Verniaiev won gold on the parallel bars and silver in the all-around at the Rio Olympics, claiming the country's first Olympic all-around gymnastics medal since 2000." },
  { country: "ua", year: 2016, category: "Science & tech", text: "In November, engineers slid the colossal 36,000-tonne New Safe Confinement arch over the destroyed Chernobyl reactor, completing one of the largest movable structures ever built." },
  { country: "ua", year: 2016, category: "Science & tech", text: "The transparent electronic procurement system ProZorro, born from a volunteer anti-corruption project, became mandatory for state purchases and won that year's World Procurement Award." },
  { country: "ua", year: 2017, category: "Everyday life", text: "From 11 June, holders of biometric passports could travel visa-free to the European Union's Schengen area for short stays, fulfilling a key promise of the Euromaidan." },
  { country: "ua", year: 2017, category: "Culture", text: "The war drama 'Cyborgs: Heroes Never Die' premiered on the third anniversary of the airport's fall, part of a wave of homegrown cinema confronting the conflict in the east." },
  { country: "ua", year: 2018, category: "Politics", text: "On 15 December a unification council in Kyiv's ancient St Sophia's Cathedral merged the country's rival Orthodox jurisdictions into a single independent Orthodox Church of Ukraine and elected the 39-year-old Metropolitan Epiphanius as its head, a historic break from centuries of church subordination to Moscow." },
  { country: "ua", year: 2018, category: "Upheaval", text: "On 25 November Russian coast-guard vessels rammed, fired on and seized three Ukrainian navy boats and their 24 crew off the coast of occupied Crimea in the Kerch Strait, prompting President Petro Poroshenko to declare martial law across the country's border and coastal regions." },
  { country: "ua", year: 2018, category: "Sport", text: "On 26 May the capital's Olimpiyskiy Stadium hosted the Champions League final, where Real Madrid beat Liverpool 3-1 to lift European club football's greatest prize for a third year running before a worldwide television audience." },
  { country: "ua", year: 2019, category: "Culture", text: "On 6 January in Istanbul, the Ecumenical Patriarch Bartholomew handed Metropolitan Epiphanius the 'Tomos,' the decree granting the newly unified Orthodox Church independence from Moscow." },
  { country: "ua", year: 2019, category: "Politics", text: "Comedian Volodymyr Zelensky, who had played a fictional president on the hit TV series 'Servant of the People,' won the real presidency in a landslide with about 73 percent of the runoff vote." },
  { country: "ua", year: 2019, category: "Science & tech", text: "The New Safe Confinement over Chernobyl's ruined reactor passed its final commissioning tests in April and was later formally handed over to the state, sealing the site for a century." },
  { country: "ua", year: 2019, category: "People", text: "In September, filmmaker Oleg Sentsov walked free at last, released to a hero's welcome in a large prisoner exchange between Russia and Ukraine." },
  { country: "ua", year: 2020, category: "Upheaval", text: "On January 8 a passenger jet bound for Kyiv was shot down minutes after taking off from Tehran by two Iranian missiles, killing all 176 people aboard, many of them students and families travelling home via Canada." },
  { country: "ua", year: 2020, category: "Science & tech", text: "The state rolled out a smartphone app called Diia in February that gathered government services in one place, and within a year the country became the first in the world to give digital passports the same legal force as paper documents." },
  { country: "ua", year: 2020, category: "Everyday life", text: "A nationwide coronavirus lockdown shuttered schools, cafes and the Kyiv metro in spring, the first time the capital's underground had fully stopped running since it opened decades earlier." },
  { country: "ua", year: 2021, category: "Politics", text: "From January a long-debated law mandating Ukrainian as the language of customer service in shops, restaurants and the public sphere came into force, requiring waiters and cashiers to address customers in Ukrainian first." },
  { country: "ua", year: 2021, category: "Sport", text: "Coached by football legend Andriy Shevchenko, the national team reached the quarter-finals of the European Championship for the first time, after Artem Dovbyk's stoppage-time header in the 121st minute beat Sweden in extra time." },
  { country: "ua", year: 2021, category: "Everyday life", text: "By spring the population had fallen to roughly 41 million, a steady decline driven by low birth rates and emigration that long predated the war to come." },
  { country: "ua", year: 2022, category: "Upheaval", text: "In the early hours of February 24, missiles struck airports and cities and columns of tanks rolled toward the capital from Belarus, beginning a full-scale invasion that the defenders repelled outside Kyiv within weeks." },
  { country: "ua", year: 2022, category: "Upheaval", text: "After Russian troops withdrew from the towns north of the capital in early April, the streets of Bucha were found strewn with the bodies of executed civilians, evidence of atrocities that shocked the world." },
  { country: "ua", year: 2022, category: "Upheaval", text: "The port city of Mariupol was besieged and bombarded into rubble, and in mid-to-late May the last defenders holed up in the cavernous Azovstal steelworks were ordered to surrender after weeks underground." },
  { country: "ua", year: 2022, category: "Politics", text: "On June 23 the European Council granted the country official candidate status for membership of the European Union, a step long thought to be decades away." },
  { country: "ua", year: 2022, category: "Everyday life", text: "A UN- and Turkey-brokered deal signed in Istanbul in July reopened Black Sea ports so that millions of tonnes of grain stranded in Odesa could again sail to world markets." },
  { country: "ua", year: 2022, category: "Culture", text: "The folk-rap group Kalush Orchestra won the Eurovision Song Contest in Turin in May with 'Stefania,' a song its frontman had written for his mother that took on new meaning as a wartime anthem." },
  { country: "ua", year: 2022, category: "Everyday life", text: "From October waves of missile and drone strikes on power plants plunged cities into rolling blackouts, and households learned to live by generators, candles and the hum of charging stations through a freezing winter." },
  { country: "ua", year: 2023, category: "Upheaval", text: "In the early hours of June 6 the massive Kakhovka dam on the Dnipro was breached, unleashing catastrophic floods downstream across the Kherson region and draining the reservoir that fed farms and cooling ponds." },
  { country: "ua", year: 2023, category: "Upheaval", text: "A much-anticipated summer counteroffensive ground slowly against dense Russian minefields and trenches, and by November the top commander publicly described the front as a stalemate." },
  { country: "ua", year: 2023, category: "Culture", text: "Mstyslav Chernov's harrowing documentary '20 Days in Mariupol,' shot by Associated Press journalists trapped in the besieged city, was chosen as the country's Oscar submission." },
  { country: "ua", year: 2024, category: "Sport", text: "In Riyadh in May the boxer Oleksandr Usyk outpointed Tyson Fury to become the first undisputed heavyweight world champion of the four-belt era, the first man to unify the division in 24 years." },
  { country: "ua", year: 2024, category: "Upheaval", text: "On August 6 troops surged across the border into Russia's Kursk region, the first foreign occupation of Russian soil since the Second World War, seizing dozens of settlements before the line stabilised." },
  { country: "ua", year: 2024, category: "Culture", text: "At Eurovision in Malmo the duo alyona alyona and Jerry Heil finished third with 'Teresa & Maria,' a song of resilience blending rap and soaring vocals." },
  { country: "ua", year: 2024, category: "Culture", text: "The documentary '20 Days in Mariupol' won the Academy Award for Best Documentary Feature, the first Oscar in the country's history, with director Mstyslav Chernov saying he wished he had never made it." },
  { country: "ua", year: 2025, category: "Politics", text: "A February meeting in the Oval Office intended to seal a minerals agreement collapsed into an extraordinary televised shouting match, though a reworked deal creating a joint reconstruction fund was eventually signed at the end of April." },
  { country: "ua", year: 2025, category: "Science & tech", text: "On June 1 an audacious operation codenamed Spiderweb launched 117 small drones from trucks deep inside Russia, striking strategic-bomber bases and destroying or damaging dozens of aircraft worth billions." },
  { country: "ua", year: 2025, category: "Politics", text: "Direct talks resumed in Istanbul for the first time since 2022, and although no ceasefire emerged, the rounds produced large prisoner exchanges with each side returning at least a thousand captives." },
  { country: "ua", year: 2025, category: "Everyday life", text: "A fourth winter of war saw families again stockpiling power banks and portable stoves as repeated strikes on the grid forced scheduled blackouts across the country's cities." },
];
